11	} from '@nestjs/common';
12	import { InjectRepository } from '@nestjs/typeorm';
13	import { Repository } from 'typeorm';
14	import { Request } from 'express';
15	import { Public } from '../common/decorators/public.decorator';
16	import { IPaymentConnector, PAYMENT_CONNECTOR } from './interfaces/payment-connector.interface';
17	import { PaymentIdempotencyKey } from './entities/payment-idempotency-key.entity';
18	import { PaymentCallbackDto } from './dto/payment-callback.dto';
19	
20	@Controller('payments')
21	export class PaymentCallbackController {
22	  constructor(
23	    @Inject(PAYMENT_CONNECTOR)
24	    private readonly connector: IPaymentConnector,
25	    @InjectRepository(PaymentIdempotencyKey)
26	    private readonly idempotencyRepo: Repository<PaymentIdempotencyKey>,
27	  ) {}
28	
29	  /**
30	   * Receives inbound payment-provider webhooks / callbacks.
31	   *
32	   * - Marked @Public() — callbacks arrive without a user JWT.
33	   * - Signature is verified via `connector.verifyCallback()`; the noop connector
34	   *   always returns true so no external dependency is needed locally.
35	   * - Idempotent: a duplicate callback with the same key returns the stored result
36	   *   without any side effects.
37	   * - The idempotency key is resolved from (in order of preference):
38	   *     1. `body.idempotencyKey`
39	   *     2. `X-Idempotency-Key` request header
40	   */
41	  @Public()
42	  @Post('callback')
43	  @HttpCode(HttpStatus.OK)
44	  async handleCallback(
45	    @Body() body: PaymentCallbackDto,
46	    @Req() req: Request,
47	  ): Promise<{
48	    processed: boolean;
49	    alreadyProcessed: boolean;
50	    result: Record<string, unknown>;
51	  }> {
52	    // Verify provider signature — noop always passes; real connectors validate HMAC/JWT
53	    const headers = req.headers as Record<string, string>;
54	    if (!this.connector.verifyCallback(headers, body)) {
55	      throw new UnauthorizedException('Invalid callback signature');
56	    }
57	
58	    // Resolve idempotency key
59	    const key =
60	      body.idempotencyKey?.trim() || (headers['x-idempotency-key'] ?? '').trim();
61	    if (!key) {
62	      throw new BadRequestException(
63	        'Missing idempotency key — supply body.idempotencyKey or X-Idempotency-Key header',
64	      );
65	    }
66	
67	    // Idempotency check: return cached result for duplicate deliveries
68	    const existing = await this.idempotencyRepo.findOne({ where: { key } });
69	    if (existing) {
70	      return {
71	        processed: true,
72	        alreadyProcessed: true,
73	        result: existing.result as Record<string, unknown>,
74	      };
75	    }
76	
77	    // Process the callback (connector-specific logic would go here for real providers)
78	    const result: Record<string, unknown> = {
79	      success: true,
80	      event: body.event ?? 'unknown',
81	      connectorName: body.connectorName ?? this.connector.name,
82	      processedAt: new Date().toISOString(),
83	    };
84	
85	    await this.idempotencyRepo.save({
86	      key,
87	      connectorName: body.connectorName ?? this.connector.name,
88	      operation: `CALLBACK:${body.event ?? 'unknown'}`,
89	      result,
90	    });
91	
92	    return { processed: true, alreadyProcessed: false, result };
93	  }
94	}
