1	/**
2	 * Integration tests for the payment callback endpoint.
3	 *
4	 * Covers:
5	 *  - Valid callback is processed and stored (200)
6	 *  - Duplicate callback with the same idempotency key returns cached result without re-processing
7	 *  - Missing idempotency key → 400
8	 *  - Failed connector signature verification → 401
9	 *  - Idempotency key resolved from X-Idempotency-Key header when body key is absent
10	 */
11	
12	process.env.JWT_SECRET = 'callback-test-secret-32chars-xxxx!!';
13	
14	import * as request from 'supertest';
15	import * as cookieParser from 'cookie-parser';
16	import { INestApplication, ValidationPipe } from '@nestjs/common';
17	import { APP_GUARD } from '@nestjs/core';
18	import { JwtModule } from '@nestjs/jwt';
19	import { PassportModule } from '@nestjs/passport';
20	import { Test } from '@nestjs/testing';
21	import { getRepositoryToken } from '@nestjs/typeorm';
22	
23	import { PaymentCallbackController } from './payment-callback.controller';
24	import { PAYMENT_CONNECTOR, IPaymentConnector } from './interfaces/payment-connector.interface';
25	import { PaymentIdempotencyKey } from './entities/payment-idempotency-key.entity';
26	import { JwtAuthGuard } from '../common/guards/jwt-auth.guard';
27	import { RolesGuard } from '../common/guards/roles.guard';
28	import { JwtStrategy } from '../auth/strategies/jwt.strategy';
29	
30	describe('POST /api/payments/callback', () => {
31	  let app: INestApplication;
32	
33	  // Connector mock — by default verifyCallback returns true (noop behaviour)
34	  const mockConnector: IPaymentConnector = {
35	    name: 'noop',
36	    processPayment: jest.fn(),
37	    processRefund: jest.fn(),
38	    getStatus: jest.fn(),
39	    verifyCallback: jest.fn().mockReturnValue(true),
40	  };
41	
42	  // idempotency key store — starts empty
43	  const stored: Map<string, PaymentIdempotencyKey> = new Map();
44	  const idempotencyRepo = {
45	    findOne: jest.fn(async ({ where: { key } }: { where: { key: string } }) =>
46	      stored.get(key) ?? null,
47	    ),
48	    save: jest.fn(async (data: Partial<PaymentIdempotencyKey>) => {
49	      const record = { ...data } as PaymentIdempotencyKey;
50	      stored.set(data.key!, record);
51	      return record;
52	    }),
53	  };
54	
55	  beforeAll(async () => {
56	    const module = await Test.createTestingModule({
57	      imports: [
58	        PassportModule,
59	        JwtModule.register({
60	          secret: process.env.JWT_SECRET,
61	          signOptions: { expiresIn: '15m' },
62	        }),
63	      ],
64	      controllers: [PaymentCallbackController],
65	      providers: [
66	        JwtStrategy,
67	        { provide: PAYMENT_CONNECTOR, useValue: mockConnector },
68	        { provide: getRepositoryToken(PaymentIdempotencyKey), useValue: idempotencyRepo },
69	        { provide: APP_GUARD, useClass: JwtAuthGuard },
70	        { provide: APP_GUARD, useClass: RolesGuard },
71	      ],
72	    }).compile();
73	
74	    app = module.createNestApplication();
75	    app.setGlobalPrefix('api');
76	    app.use(cookieParser());
77	    app.useGlobalPipes(
78	      new ValidationPipe({ whitelist: true, forbidNonWhitelisted: true, transform: true }),
79	    );
80	    await app.init();
81	  });
82	
83	  afterAll(() => app.close());
84	
85	  beforeEach(() => {
86	    stored.clear();
87	    jest.clearAllMocks();
88	    (mockConnector.verifyCallback as jest.Mock).mockReturnValue(true);
89	  });
90	
91	  // ── Happy path ─────────────────────────────────────────────────────────────
92	
93	  it('returns 200 and processes a new callback', async () => {
94	    const res = await request(app.getHttpServer())
95	      .post('/api/payments/callback')
96	      .send({
97	        idempotencyKey: 'unique-key-001',
98	        connectorName: 'noop',
99	        event: 'payment.succeeded',
100	        payload: { amount: 500 },
101	      });
102	
103	    expect(res.status).toBe(200);
104	    expect(res.body.processed).toBe(true);
105	    expect(res.body.alreadyProcessed).toBe(false);
106	    expect(res.body.result.event).toBe('payment.succeeded');
107	    expect(res.body.result.success).toBe(true);
108	  });
109	
110	  // ── Idempotency: duplicate callback ────────────────────────────────────────
111	
112	  it('returns the cached result without re-processing on a duplicate callback', async () => {
113	    // First call
114	    await request(app.getHttpServer())
115	      .post('/api/payments/callback')
116	      .send({ idempotencyKey: 'duplicate-key', event: 'payment.succeeded' });
117	
118	    // Duplicate call — same key
119	    const res = await request(app.getHttpServer())
120	      .post('/api/payments/callback')
121	      .send({ idempotencyKey: 'duplicate-key', event: 'payment.succeeded' });
122	
123	    expect(res.status).toBe(200);
124	    expect(res.body.alreadyProcessed).toBe(true);
125	    // save must have been called only once (for the first call)
126	    expect(idempotencyRepo.save).toHaveBeenCalledTimes(1);
127	  });
128	
129	  // ── Idempotency key from header ─────────────────────────────────────────────
130	
131	  it('resolves idempotency key from X-Idempotency-Key header when body key is absent', async () => {
132	    const res = await request(app.getHttpServer())
133	      .post('/api/payments/callback')
134	      .set('X-Idempotency-Key', 'header-key-999')
135	      .send({ event: 'refund.created' });
136	
137	    expect(res.status).toBe(200);
138	    expect(res.body.alreadyProcessed).toBe(false);
139	    expect(stored.has('header-key-999')).toBe(true);
140	  });
141	
142	  // ── Missing idempotency key → 400 ──────────────────────────────────────────
143	
144	  it('returns 400 when no idempotency key is provided in body or header', async () => {
145	    const res = await request(app.getHttpServer())
146	      .post('/api/payments/callback')
147	      .send({ event: 'payment.succeeded' });
148	
149	    expect(res.status).toBe(400);
150	  });
151	
152	  // ── Invalid signature → 401 ────────────────────────────────────────────────
153	
154	  it('returns 401 when connector signature verification fails', async () => {
155	    (mockConnector.verifyCallback as jest.Mock).mockReturnValue(false);
156	
157	    const res = await request(app.getHttpServer())
158	      .post('/api/payments/callback')
159	      .send({ idempotencyKey: 'sig-fail-key', event: 'payment.succeeded' });
160	
161	    expect(res.status).toBe(401);
162	    // Nothing should have been stored
163	    expect(stored.size).toBe(0);
164	  });
165	});
