18	import { NotificationService } from '../notifications/notification.service';
19	import { DataQualityService } from '../data-quality/data-quality.service';
20	import { CreateArticleDto } from './dto/create-article.dto';
21	import { UpdateArticleDto, PromoteArticleDto } from './dto/update-article.dto';
22	import { QueryArticlesDto } from './dto/query-articles.dto';
23	
24	@Injectable()
25	export class KnowledgeBaseService {
26	  constructor(
27	    @InjectRepository(Article)
28	    private readonly articleRepo: Repository<Article>,
29	    @InjectRepository(ArticleVersion)
30	    private readonly versionRepo: Repository<ArticleVersion>,
31	    @InjectRepository(UserFavorite)
32	    private readonly favoriteRepo: Repository<UserFavorite>,
33	    private readonly dataSource: DataSource,
34	    private readonly auditService: AuditService,
35	    private readonly notificationService: NotificationService,
36	    private readonly dataQuality: DataQualityService,
37	  ) {}
38	
39	  // ── Slug generation ───────────────────────────────────────────────────────
40	
41	  private async generateUniqueSlug(title: string): Promise<string> {
42	    const base = title
43	      .toLowerCase()
44	      .replace(/[^a-z0-9\s-]/g, '')
45	      .replace(/\s+/g, '-')
46	      .replace(/-+/g, '-')
47	      .trim()
48	      .slice(0, 80);
49	
50	    let slug = base || 'article';
51	    let attempt = 0;
52	    while (await this.articleRepo.findOne({ where: { slug } })) {
53	      slug = `${base}-${++attempt}`;
54	    }
55	    return slug;
56	  }
57	
58	  // ── Visibility helpers ────────────────────────────────────────────────────
59	
60	  private buildVisibilityCondition(
61	    qb: ReturnType<typeof this.articleRepo.createQueryBuilder>,
62	    userId: string,
63	    userRole: string,
64	  ) {
65	    if (userRole === Role.ADMINISTRATOR) {
66	      // Admin sees everything except ARCHIVED (still accessible by ID)
67	      qb.andWhere('a.status != :archived', { archived: ArticleStatus.ARCHIVED });
68	      return;
69	    }
70	    if (userRole === Role.PLANT_CARE_SPECIALIST) {
71	      qb.andWhere(
72	        '(a.status = :storewide OR a.status = :specialist OR (a.status = :draft AND a.authorId = :uid))',
73	        {
74	          storewide: ArticleStatus.STOREWIDE,
75	          specialist: ArticleStatus.SPECIALIST_ONLY,
76	          draft: ArticleStatus.DRAFT,
77	          uid: userId,
78	        },
79	      );
80	      return;
81	    }
82	    // All other roles: STOREWIDE + own DRAFTs
83	    qb.andWhere(
84	      '(a.status = :storewide OR (a.status = :draft AND a.authorId = :uid))',
85	      { storewide: ArticleStatus.STOREWIDE, draft: ArticleStatus.DRAFT, uid: userId },
86	    );
87	  }
88	
89	  private canViewArticle(article: Article, userId: string, userRole: string): boolean {
90	    if (userRole === Role.ADMINISTRATOR) return true;
91	    if (article.status === ArticleStatus.ARCHIVED) return false;
92	    if (article.status === ArticleStatus.STOREWIDE) return true;
93	    if (article.status === ArticleStatus.SPECIALIST_ONLY && userRole === Role.PLANT_CARE_SPECIALIST)
94	      return true;
95	    if (article.status === ArticleStatus.DRAFT && article.authorId === userId) return true;
96	    return false;
97	  }
98	
99	  // ── CRUD ──────────────────────────────────────────────────────────────────
100	
101	  async create(userId: string, dto: CreateArticleDto): Promise<Article> {
102	    const slug = await this.generateUniqueSlug(dto.title);
103	
104	    const article = await this.dataSource.transaction(async (manager) => {
105	      const a = manager.create(Article, {
106	        title: dto.title,
107	        slug,
108	        category: dto.category ?? ArticleCategory.GENERAL,
109	        content: dto.content,
110	        tags: dto.tags ?? [],
111	        status: ArticleStatus.DRAFT,
112	        authorId: userId,
113	        currentVersionId: null,
114	      });
115	      const saved = await manager.save(Article, a);
116	
117	      // Create initial version
118	      const v = manager.create(ArticleVersion, {
119	        articleId: saved.id,
120	        versionNumber: 1,
121	        title: dto.title,
122	        content: dto.content,
123	        changeSummary: dto.changeSummary ?? 'Initial version',
124	        createdBy: userId,
125	      });
126	      const savedV = await manager.save(ArticleVersion, v);
127	      await manager.update(Article, saved.id, { currentVersionId: savedV.id });
128	      saved.currentVersionId = savedV.id;
129	      return saved;
130	    });
131	
132	    const fingerprint = this.dataQuality.generateFingerprint([article.title]);
133	    await this.articleRepo.update(article.id, { fingerprint });
134	    this.dataQuality.checkForDuplicates('Article', article.id, fingerprint).catch(() => undefined);
135	
136	    await this.auditService.log(userId, AuditAction.ARTICLE_CREATED, 'Article', article.id, {
137	      title: article.title,
138	      slug: article.slug,
139	    });
140	
141	    return this.findById(article.id, userId, Role.ADMINISTRATOR);
142	  }
