144	  async update(id: string, userId: string, dto: UpdateArticleDto): Promise<Article> {
145	    const article = await this.articleRepo.findOne({ where: { id } });
146	    if (!article) throw new NotFoundException('Article not found');
147	    if (article.status === ArticleStatus.ARCHIVED)
148	      throw new ForbiddenException('Cannot edit an archived article');
149	
150	    await this.dataSource.transaction(async (manager) => {
151	      if (dto.title !== undefined) article.title = dto.title;
152	      if (dto.category !== undefined) article.category = dto.category;
153	      if (dto.content !== undefined) article.content = dto.content;
154	      if (dto.tags !== undefined) article.tags = dto.tags;
155	
156	      await manager.save(Article, article);
157	
158	      // Get next version number
159	      const maxResult = await manager
160	        .createQueryBuilder()
161	        .select('MAX(av."versionNumber")', 'max')
162	        .from(ArticleVersion, 'av')
163	        .where('av."articleId" = :id', { id })
164	        .getRawOne<{ max: string }>();
165	      const nextVersion = (parseInt(maxResult?.max ?? '0', 10) || 0) + 1;
166	
167	      const v = manager.create(ArticleVersion, {
168	        articleId: id,
169	        versionNumber: nextVersion,
170	        title: article.title,
171	        content: article.content,
172	        changeSummary: dto.changeSummary ?? null,
173	        createdBy: userId,
174	      });
175	      const savedV = await manager.save(ArticleVersion, v);
176	      await manager.update(Article, id, { currentVersionId: savedV.id });
177	    });
178	
179	    const fingerprint = this.dataQuality.generateFingerprint([article.title]);
180	    await this.articleRepo.update(id, { fingerprint });
181	    this.dataQuality.checkForDuplicates('Article', id, fingerprint).catch(() => undefined);
182	
183	    await this.auditService.log(userId, AuditAction.ARTICLE_UPDATED, 'Article', id, {
184	      title: article.title,
185	    });
186	
187	    return this.findById(id, userId, Role.ADMINISTRATOR);
188	  }
189	
190	  async promote(id: string, userId: string, dto: PromoteArticleDto): Promise<Article> {
191	    const article = await this.articleRepo.findOne({ where: { id } });
192	    if (!article) throw new NotFoundException('Article not found');
193	
194	    const prevStatus = article.status;
195	    await this.articleRepo.update(id, { status: dto.status });
196	
197	    const action =
198	      dto.status === ArticleStatus.ARCHIVED
199	        ? AuditAction.ARTICLE_ARCHIVED
200	        : AuditAction.ARTICLE_PROMOTED;
201	
202	    await this.auditService.log(userId, action, 'Article', id, {
203	      title: article.title,
204	      previousStatus: prevStatus,
205	      newStatus: dto.status,
206	    });
207	
208	    if (
209	      article.authorId &&
210	      (dto.status === ArticleStatus.STOREWIDE || dto.status === ArticleStatus.SPECIALIST_ONLY)
211	    ) {
212	      const audience =
213	        dto.status === ArticleStatus.STOREWIDE ? 'all staff' : 'plant care specialists';
214	      await this.notificationService.emit(
215	        article.authorId,
216	        NotificationType.ARTICLE_PUBLISHED,
217	        'Article Published',
218	        `Your article "${article.title}" has been published and is now visible to ${audience}.`,
219	        { type: 'Article', id },
220	      );
221	    }
222	
223	    return this.findById(id, userId, Role.ADMINISTRATOR);
224	  }
225	
226	  // ── Queries ───────────────────────────────────────────────────────────────
227	
228	  async findAll(userId: string, userRole: string, query: QueryArticlesDto) {
229	    const page = parseInt(query.page || '1', 10);
230	    const limit = Math.min(parseInt(query.limit || '20', 10), 100);
231	    const skip = (page - 1) * limit;
232	
233	    const qb = this.articleRepo
234	      .createQueryBuilder('a')
235	      .leftJoinAndSelect('a.author', 'author')
236	      .orderBy('a.updatedAt', 'DESC')
237	      .skip(skip)
238	      .take(limit);
239	
240	    this.buildVisibilityCondition(qb, userId, userRole);
241	
242	    if (query.search) {
243	      qb.andWhere(
244	        '(a.title ILIKE :search OR a.content ILIKE :search)',
245	        { search: `%${query.search}%` },
246	      );
247	    }
248	    if (query.category) qb.andWhere('a.category = :category', { category: query.category });
249	    if (query.status && userRole === Role.ADMINISTRATOR)
250	      qb.andWhere('a.status = :status', { status: query.status });
251	    if (query.tag)
252	      qb.andWhere(':tag = ANY(a.tags)', { tag: query.tag });
253	
254	    const [data, total] = await qb.getManyAndCount();
255	    return { data, meta: { page, limit, total, totalPages: Math.ceil(total / limit) } };
256	  }
257	
258	  async findById(id: string, userId: string, userRole: string): Promise<Article> {
259	    const article = await this.articleRepo.findOne({
260	      where: { id },
261	      relations: ['author'],
262	    });
263	    if (!article) throw new NotFoundException('Article not found');
264	    if (!this.canViewArticle(article, userId, userRole)) {
265	      throw new NotFoundException('Article not found');
266	    }
267	    return article;
268	  }
269	
270	  async findBySlug(slug: string, userId: string, userRole: string): Promise<Article> {
271	    const article = await this.articleRepo.findOne({ where: { slug }, relations: ['author'] });
272	    if (!article) throw new NotFoundException('Article not found');
273	    if (!this.canViewArticle(article, userId, userRole)) {
274	      throw new NotFoundException('Article not found');
275	    }
276	    return article;
277	  }
