279	  // ── Versions ──────────────────────────────────────────────────────────────
280	
281	  async getVersions(articleId: string, userId: string, userRole: string) {
282	    await this.findById(articleId, userId, userRole); // visibility check
283	    return this.versionRepo.find({
284	      where: { articleId },
285	      order: { versionNumber: 'DESC' },
286	      relations: ['creator'],
