290	  async getVersion(
291	    articleId: string,
292	    versionNumber: number,
293	    userId: string,
294	    userRole: string,
295	  ): Promise<ArticleVersion> {
296	    await this.findById(articleId, userId, userRole);
297	    const version = await this.versionRepo.findOne({
298	      where: { articleId, versionNumber },
299	      relations: ['creator'],
300	    });
301	    if (!version) throw new NotFoundException('Version not found');
302	    return version;
