306	
307	  async addFavorite(userId: string, articleId: string): Promise<void> {
308	    const article = await this.articleRepo.findOne({ where: { id: articleId } });
309	    if (!article) throw new NotFoundException('Article not found');
310	    const existing = await this.favoriteRepo.findOne({ where: { userId, articleId } });
311	    if (existing) return; // idempotent
312	    await this.favoriteRepo.save({ userId, articleId });
313	  }
