7	@Injectable()
8	export class NoOpPaymentConnector implements IPaymentConnector {
9	  readonly name = 'noop';
10	
11	  constructor(
12	    @InjectRepository(PaymentIdempotencyKey)
13	    private readonly idempotencyRepo: Repository<PaymentIdempotencyKey>,
14	  ) {}
15	
16	  private async deduplicate(
17	    key: string,
18	    operation: string,
19	    produce: () => PaymentResult,
20	  ): Promise<PaymentResult> {
21	    const existing = await this.idempotencyRepo.findOne({ where: { key } });
22	    if (existing) return existing.result as unknown as PaymentResult;
23	
24	    const result = produce();
25	    await this.idempotencyRepo.save({
26	      key,
27	      connectorName: this.name,
28	      operation,
29	      result: result as unknown as Record<string, unknown>,
30	    });
31	    return result;
32	  }
33	
34	  async processPayment(
35	    idempotencyKey: string,
36	    supplierId: string,
37	    amount: number,
38	    reference: string,
39	  ): Promise<PaymentResult> {
40	    void supplierId;
41	    void amount;
42	    void reference;
43	    return this.deduplicate(idempotencyKey, 'PAYMENT', () => ({
44	      success: true,
45	      transactionId: `noop-pay-${idempotencyKey}`,
46	      message: 'NoOp connector: payment recorded locally, no external call made',
47	    }));
48	  }
49	
50	  async processRefund(
51	    idempotencyKey: string,
52	    supplierId: string,
53	    amount: number,
54	    reference: string,
55	  ): Promise<PaymentResult> {
56	    void supplierId;
57	    void amount;
58	    void reference;
59	    return this.deduplicate(idempotencyKey, 'REFUND', () => ({
60	      success: true,
61	      transactionId: `noop-ref-${idempotencyKey}`,
62	      message: 'NoOp connector: refund recorded locally, no external call made',
63	    }));
64	  }
65	
66	  async getStatus(transactionId: string): Promise<PaymentResult> {
67	    void transactionId;
68	    return { success: true, message: 'NoOp connector: status tracking not available' };
69	  }
70	
71	  /**
72	   * NoOp signature verification — always accepts the callback.
73	   * Real connectors would check `headers['x-signature']` against an HMAC of `body`.
74	   */
75	  verifyCallback(_headers: Record<string, string>, _body: unknown): boolean {
76	    return true;
77	  }
78	}
