/**
 * E2E login flow tests.
 *
 * These tests require the full stack to be running:
 *   - Backend:  cd repo/server && npm run start:dev   (port 3001)
 *   - Frontend: cd repo/client && npm run dev         (port 3000)
 *
 * Run with: cd repo && npm run test:e2e
 */

test.describe('Login flow', () => {
  test.beforeEach(async ({ page }) => {
    await page.goto('/login');
  });

  test('login page renders username and password fields', async ({ page }) => {
    // The login form must contain both input fields and a submit button.
    await expect(page.locator('input[name="username"], input[type="text"], input[id*="user"]').first()).toBeVisible();
    await expect(page.locator('input[type="password"]')).toBeVisible();
    await expect(page.locator('button[type="submit"], button:has-text("Login"), button:has-text("Sign in")').first()).toBeVisible();
  });

  test('invalid credentials show an error message', async ({ page }) => {
    await page.locator('input[name="username"], input[type="text"], input[id*="user"]').first().fill('notauser');
    await page.locator('input[type="password"]').fill('wrongpassword');
    await page.locator('button[type="submit"], button:has-text("Login"), button:has-text("Sign in")').first().click();

    // Expect an error indicator — could be a text message or an aria-invalid attribute.
    const errorVisible = await page
      .locator('[role="alert"], .error, [data-testid*="error"], [class*="error"]')
      .first()
      .isVisible()
      .catch(() => false);

    // Also check for a 4xx response rendered to user or inline validation
    const pageText = await page.textContent('body');
    const hasErrorIndicator =
      errorVisible ||
      /invalid|incorrect|unauthorized|wrong|credentials/i.test(pageText ?? '');

    expect(hasErrorIndicator).toBe(true);
  });

  test('successful login with valid credentials redirects away from /login', async ({ page }) => {
    // Uses the default bootstrap admin credentials.
    // Set ADMIN_BOOTSTRAP_USERNAME / ADMIN_BOOTSTRAP_PASSWORD env vars on the
    // server to match what you provide here when seeding the database.
    const username = process.env.E2E_ADMIN_USER ?? 'admin';
    const password = process.env.E2E_ADMIN_PASS ?? 'admin';

    await page.locator('input[name="username"], input[type="text"], input[id*="user"]').first().fill(username);
    await page.locator('input[type="password"]').fill(password);
    await page.locator('button[type="submit"], button:has-text("Login"), button:has-text("Sign in")').first().click();

    // After a successful login the user should be redirected off /login.
    await page.waitForURL((url) => !url.pathname.includes('/login'), { timeout: 5000 });
    expect(page.url()).not.toContain('/login');
  });
});
"}

