/**
 * Playwright E2E configuration for the GreenLeaf Operations Suite.
 *
 * The `webServer` block starts a dedicated Vite dev server on port 3100
 * so E2E tests are isolated from the developer's running dev server.
 * The Vite proxy forwards /api/* to the NestJS backend at 127.0.0.1:3001.
 *
 * Prerequisites:
 *   1. Backend running:  cd repo/server && npm run start:dev
 *   2. Demo seed loaded: cd repo/server && npm run seed:demo
 *   3. Playwright browsers installed: cd repo && npx playwright install chromium
 *
 * Run:
 *   cd repo && npm run test:e2e
 */
export default defineConfig({
  testDir: './tests/e2e',
  fullyParallel: false,
  retries: 0,
  workers: 1,
  reporter: 'list',
  timeout: 30_000,

  webServer: {
    command: 'npx vite --port 3100',
    cwd: './client',
    url: 'http://localhost:3100',
    reuseExistingServer: true,
    timeout: 15_000,
  },

  use: {
    baseURL: 'http://localhost:3100',
    trace: 'on-first-retry',
    screenshot: 'only-on-failure',
  },

  projects: [
    {
      name: 'chromium',
      use: { ...devices['Desktop Chrome'] },
    },
  ],
});
"}

