23	
24	  @Public()
25	  @Throttle({ default: { ttl: 900_000, limit: 10 } })
26	  @UseGuards(AuthGuard('local'))
27	  @Post('login')
28	  @HttpCode(HttpStatus.OK)
29	  async login(
30	    @Req() req: Request,
31	    @Res({ passthrough: true }) res: Response,
32	    @Body() _loginDto: LoginDto,
33	  ) {
34	    const result = await this.authService.login(req.user as any);
35	
36	    res.cookie('refresh_token', result.refreshToken, {
37	      httpOnly: true,
38	      secure: process.env.NODE_ENV === 'production',
39	      sameSite: 'strict',
40	      maxAge: 30 * 60 * 1000,
41	      path: '/api/auth',
42	    });
43	
44	    return {
45	      accessToken: result.accessToken,
46	      user: result.user,
47	    };
48	  }
49	
50	  @Public()
51	  @Post('refresh')
52	  @HttpCode(HttpStatus.OK)
53	  async refresh(@Req() req: Request, @Res({ passthrough: true }) res: Response) {
54	    const refreshToken = req.cookies?.refresh_token;
55	    if (!refreshToken) {
56	      throw new UnauthorizedException('No refresh token');
57	    }
58	
59	    const result = await this.authService.refresh(refreshToken);
60	
61	    // Set the rotated refresh token in the cookie
62	    res.cookie('refresh_token', result.refreshToken, {
63	      httpOnly: true,
64	      secure: process.env.NODE_ENV === 'production',
65	      sameSite: 'strict',
66	      maxAge: 30 * 60 * 1000,
67	      path: '/api/auth',
68	    });
69	
70	    return { accessToken: result.accessToken, user: result.user };
71	  }
72	
73	  @Public()
74	  @Post('logout')
75	  @HttpCode(HttpStatus.OK)
76	  async logout(@Req() req: Request, @Res({ passthrough: true }) res: Response) {
77	    const refreshToken = req.cookies?.refresh_token;
78	    if (refreshToken) {
79	      await this.authService.logout(refreshToken);
80	    }
81	    res.clearCookie('refresh_token', { path: '/api/auth' });
82	    return { message: 'Logged out' };
83	  }
