1	import {
2	  Injectable,
3	  NotFoundException,
4	  BadRequestException,
5	} from '@nestjs/common';
6	import { InjectRepository } from '@nestjs/typeorm';
7	import { Repository, DataSource } from 'typeorm';
8	import { Receipt } from './entities/receipt.entity';
9	import { ReceiptLineItem } from './entities/receipt-line-item.entity';
10	import { PurchaseOrder } from '../purchase-orders/entities/purchase-order.entity';
11	import { PurchaseOrderLineItem } from '../purchase-orders/entities/purchase-order-line-item.entity';
12	import { ReceiptStatus } from '../common/enums/receipt-status.enum';
13	import { ReceivingEntryMode } from '../common/enums/receiving-entry-mode.enum';
14	import { VarianceReasonCode } from '../common/enums/variance-reason-code.enum';
15	import { PoStatus } from '../common/enums/po-status.enum';
16	import { AuditAction } from '../common/enums/audit-action.enum';
17	import { NotificationType } from '../common/enums/notification-type.enum';
18	import { AuditService } from '../audit/audit.service';
19	import { NotificationService } from '../notifications/notification.service';
20	import { CreateReceiptDto } from './dto/create-receipt.dto';
21	import { QueryReceiptsDto } from './dto/query-receipts.dto';
22	
23	@Injectable()
24	export class ReceivingService {
25	  constructor(
26	    @InjectRepository(Receipt)
27	    private readonly receiptRepo: Repository<Receipt>,
28	    @InjectRepository(ReceiptLineItem)
29	    private readonly rliRepo: Repository<ReceiptLineItem>,
30	    private readonly dataSource: DataSource,
31	    private readonly auditService: AuditService,
32	    private readonly notificationService: NotificationService,
33	  ) {}
34	
35	  private async generateReceiptNumber(): Promise<string> {
36	    const result = await this.dataSource.query(
37	      `SELECT nextval('receipt_number_seq') as seq`,
38	    );
39	    const seq = parseInt(result[0].seq, 10);
40	    const year = new Date().getFullYear();
41	    return `REC-${year}-${String(seq).padStart(5, '0')}`;
42	  }
43	
44	  async create(userId: string, dto: CreateReceiptDto): Promise<Receipt> {
45	    const po = await this.dataSource.getRepository(PurchaseOrder).findOne({
46	      where: { id: dto.poId },
47	      relations: ['lineItems'],
48	    });
49	    if (!po) throw new NotFoundException('Purchase order not found');
50	    if (![PoStatus.ISSUED, PoStatus.PARTIALLY_RECEIVED].includes(po.status)) {
51	      throw new BadRequestException(
52	        'PO must be ISSUED or PARTIALLY_RECEIVED to receive against',
53	      );
54	    }
55	
56	    const receiptNumber = await this.generateReceiptNumber();
57	
58	    const lineItems = dto.lineItems.map((li) => {
59	      const variance = Number(li.quantityReceived) - Number(li.quantityExpected);
60	      if (variance !== 0 && (!li.varianceReasonCode || li.varianceReasonCode === VarianceReasonCode.NONE)) {
61	        throw new BadRequestException(
62	          `Variance on line item ${li.poLineItemId} requires a reason code`,
63	        );
64	      }
65	      const rli = new ReceiptLineItem();
66	      rli.poLineItemId = li.poLineItemId;
67	      rli.quantityExpected = Number(li.quantityExpected);
68	      rli.quantityReceived = Number(li.quantityReceived);
69	      rli.varianceQuantity = variance;
70	      rli.varianceReasonCode = li.varianceReasonCode ?? VarianceReasonCode.NONE;
71	      rli.varianceNotes = li.varianceNotes ?? null;
72	      rli.putawayLocationId = li.putawayLocationId ?? null;
73	      return rli;
74	    });
75	
76	    const receipt = this.receiptRepo.create({
77	      receiptNumber,
78	      poId: dto.poId,
79	      receivedBy: userId,
80	      status: ReceiptStatus.IN_PROGRESS,
81	      entryMode: dto.entryMode ?? ReceivingEntryMode.MANUAL,
82	      notes: dto.notes ?? null,
83	      lineItems,
84	    });
85	
86	    const saved = await this.receiptRepo.save(receipt);
87	
88	    await this.auditService.log(
89	      userId,
90	      AuditAction.RECEIPT_CREATED,
91	      'Receipt',
92	      saved.id,
93	      { receiptNumber: saved.receiptNumber, poId: dto.poId },
94	    );
95	
96	    return this.findById(saved.id);
97	  }
98	
99	  async complete(id: string, userId: string): Promise<Receipt> {
100	    const receipt = await this.findById(id);
101	    if (receipt.status === ReceiptStatus.COMPLETED) {
102	      throw new BadRequestException('Receipt is already completed');
103	    }
104	
105	    let newPoStatus: PoStatus = PoStatus.PARTIALLY_RECEIVED;
106	
107	    await this.dataSource.transaction(async (manager) => {
108	      // Mark receipt completed
109	      await manager.update(Receipt, id, {
110	        status: ReceiptStatus.COMPLETED,
111	        receivedAt: new Date(),
112	      });
113	
114	      // Accumulate quantityReceived increments per PO line item
115	      for (const rli of receipt.lineItems) {
116	        await manager
117	          .createQueryBuilder()
118	          .update(PurchaseOrderLineItem)
119	          .set({
120	            quantityReceived: () =>
121	              `"quantityReceived" + ${Number(rli.quantityReceived)}`,
122	          })
123	          .where('id = :id', { id: rli.poLineItemId })
124	          .execute();
125	      }
126	
127	      // Re-fetch PO line items to determine new status
128	      const po = await manager.findOne(PurchaseOrder, {
129	        where: { id: receipt.poId },
130	        relations: ['lineItems'],
131	      });
132	
133	      const allFullyReceived = po!.lineItems.every(
134	        (li) => Number(li.quantityReceived) >= Number(li.quantity),
135	      );
136	      newPoStatus = allFullyReceived
137	        ? PoStatus.FULLY_RECEIVED
138	        : PoStatus.PARTIALLY_RECEIVED;
139	
140	      await manager.update(PurchaseOrder, receipt.poId, { status: newPoStatus });
141	    });
142	
143	    await this.auditService.log(
144	      userId,
145	      AuditAction.RECEIPT_COMPLETED,
146	      'Receipt',
147	      id,
148	      { receiptNumber: receipt.receiptNumber, poId: receipt.poId, newPoStatus },
149	    );
150	
151	    await this.notificationService.emit(
152	      userId,
153	      NotificationType.RECEIPT_COMPLETED,
154	      'Receipt Completed',
155	      `Receipt ${receipt.receiptNumber} has been completed. PO status is now ${newPoStatus}.`,
156	      { type: 'Receipt', id },
157	    );
158	
159	    return this.findById(id);
160	  }
161	
162	  async findAll(query: QueryReceiptsDto) {
163	    const page = parseInt(query.page || '1', 10);
164	    const limit = Math.min(parseInt(query.limit || '20', 10), 100);
165	    const skip = (page - 1) * limit;
166	
167	    const qb = this.receiptRepo
168	      .createQueryBuilder('r')
169	      .leftJoinAndSelect('r.purchaseOrder', 'po')
170	      .leftJoinAndSelect('r.receiver', 'receiver')
171	      .leftJoinAndSelect('r.lineItems', 'lineItems')
172	      .leftJoinAndSelect('lineItems.putawayLocation', 'putawayLocation')
173	      .orderBy('r.createdAt', 'DESC')
174	      .skip(skip)
175	      .take(limit);
176	
177	    if (query.poId) {
178	      qb.andWhere('r.poId = :poId', { poId: query.poId });
179	    }
180	
181	    const [data, total] = await qb.getManyAndCount();
182	    return { data, meta: { page, limit, total, totalPages: Math.ceil(total / limit) } };
183	  }
184	
185	  async findById(id: string): Promise<Receipt> {
186	    const receipt = await this.receiptRepo.findOne({
187	      where: { id },
188	      relations: ['purchaseOrder', 'receiver', 'lineItems', 'lineItems.putawayLocation', 'lineItems.poLineItem'],
189	    });
190	    if (!receipt) throw new NotFoundException('Receipt not found');
191	    return receipt;
192	  }
193	}
