1	import {
2	  Injectable,
3	  NotFoundException,
4	  BadRequestException,
5	  ForbiddenException,
6	  Inject,
7	  forwardRef,
8	} from '@nestjs/common';
9	import { InjectRepository } from '@nestjs/typeorm';
10	import { Repository, DataSource, ILike } from 'typeorm';
11	import { PurchaseRequest } from './entities/purchase-request.entity';
12	import { PurchaseRequestLineItem } from './entities/purchase-request-line-item.entity';
13	import { Approval } from './entities/approval.entity';
14	import { RequestStatus } from '../common/enums/request-status.enum';
15	import { ApprovalAction } from '../common/enums/approval-action.enum';
16	import { AuditAction } from '../common/enums/audit-action.enum';
17	import { NotificationType } from '../common/enums/notification-type.enum';
18	import { AuditService } from '../audit/audit.service';
19	import { NotificationService } from '../notifications/notification.service';
20	import { PurchaseOrdersService } from '../purchase-orders/purchase-orders.service';
21	import { CreateRequestDto } from './dto/create-request.dto';
22	import { UpdateRequestDto } from './dto/update-request.dto';
23	import { ApprovalActionDto } from './dto/approval-action.dto';
24	import { QueryRequestsDto } from './dto/query-requests.dto';
25	
26	// Approval tier thresholds
27	const AUTO_APPROVE_LIMIT = 500;
28	const SINGLE_APPROVAL_LIMIT = 5000;
29	
30	@Injectable()
31	export class ProcurementService {
32	  constructor(
33	    @InjectRepository(PurchaseRequest)
34	    private readonly requestRepo: Repository<PurchaseRequest>,
35	    @InjectRepository(PurchaseRequestLineItem)
36	    private readonly lineItemRepo: Repository<PurchaseRequestLineItem>,
37	    @InjectRepository(Approval)
38	    private readonly approvalRepo: Repository<Approval>,
39	    private readonly dataSource: DataSource,
40	    private readonly auditService: AuditService,
41	    private readonly notificationService: NotificationService,
42	    @Inject(forwardRef(() => PurchaseOrdersService))
43	    private readonly purchaseOrdersService: PurchaseOrdersService,
44	  ) {}
45	
46	  private calculateApprovalTier(totalAmount: number): number {
47	    if (totalAmount <= AUTO_APPROVE_LIMIT) return 0;
48	    if (totalAmount <= SINGLE_APPROVAL_LIMIT) return 1;
49	    return 2;
50	  }
51	
52	  private async generateRequestNumber(): Promise<string> {
53	    const result = await this.dataSource.query(
54	      `SELECT nextval('pr_number_seq') as seq`,
55	    );
56	    const seq = parseInt(result[0].seq, 10);
57	    const year = new Date().getFullYear();
58	    return `PR-${year}-${String(seq).padStart(5, '0')}`;
59	  }
60	
61	  async findAll(query: QueryRequestsDto, userId?: string) {
62	    const page = parseInt(query.page || '1', 10);
63	    const limit = Math.min(parseInt(query.limit || '20', 10), 100);
64	    const skip = (page - 1) * limit;
65	
66	    const qb = this.requestRepo
67	      .createQueryBuilder('pr')
68	      .leftJoinAndSelect('pr.requester', 'requester')
69	      .leftJoinAndSelect('pr.supplier', 'supplier')
70	      .leftJoinAndSelect('pr.lineItems', 'lineItems');
71	
72	    if (query.status) {
73	      qb.andWhere('pr.status = :status', { status: query.status });
74	    }
75	
76	    if (query.search) {
77	      qb.andWhere(
78	        '(pr.requestNumber ILIKE :search OR pr.title ILIKE :search)',
79	        { search: `%${query.search}%` },
80	      );
81	    }
82	
83	    const sortBy = query.sortBy || 'createdAt';
84	    const sortOrder = (query.sortOrder?.toUpperCase() === 'ASC' ? 'ASC' : 'DESC') as 'ASC' | 'DESC';
85	    const allowedSorts = ['requestNumber', 'title', 'totalAmount', 'status', 'createdAt'];
86	    const orderField = allowedSorts.includes(sortBy) ? sortBy : 'createdAt';
87	
88	    qb.orderBy(`pr.${orderField}`, sortOrder);
89	    qb.skip(skip).take(limit);
90	
91	    const [data, total] = await qb.getManyAndCount();
92	
93	    return {
94	      data,
95	      meta: { page, limit, total, totalPages: Math.ceil(total / limit) },
96	    };
97	  }
98	
99	  async findById(id: string): Promise<PurchaseRequest> {
100	    const request = await this.requestRepo.findOne({
101	      where: { id },
102	      relations: ['requester', 'supplier', 'lineItems', 'approvals', 'approvals.approver'],
103	    });
104	    if (!request) throw new NotFoundException('Purchase request not found');
105	    return request;
106	  }
107	
108	  async create(dto: CreateRequestDto, userId: string): Promise<PurchaseRequest> {
109	    const requestNumber = await this.generateRequestNumber();
110	
111	    const lineItems = dto.lineItems.map((li) => {
112	      const item = new PurchaseRequestLineItem();
113	      item.itemDescription = li.itemDescription;
114	      item.quantity = li.quantity;
115	      item.unitPrice = li.unitPrice;
116	      item.totalPrice = Number((li.quantity * li.unitPrice).toFixed(2));
117	      item.catalogItemId = li.catalogItemId ?? null;
118	      return item;
119	    });
120	
121	    const totalAmount = lineItems.reduce((sum, li) => sum + Number(li.totalPrice), 0);
122	
123	    const request = this.requestRepo.create({
124	      requestNumber,
125	      title: dto.title,
126	      description: dto.description ?? null,
127	      requestedBy: userId,
128	      supplierId: dto.supplierId ?? null,
129	      lineItems,
130	      totalAmount: Number(totalAmount.toFixed(2)),
131	      status: RequestStatus.DRAFT,
132	      approvalTier: this.calculateApprovalTier(totalAmount),
133	    });
134	
135	    const saved = await this.requestRepo.save(request);
136	
137	    await this.auditService.log(userId, AuditAction.PR_CREATED, 'PurchaseRequest', saved.id, {
138	      requestNumber: saved.requestNumber,
139	      totalAmount: saved.totalAmount,
140	    });
141	
142	    return this.findById(saved.id);
143	  }
144	
145	  async update(id: string, dto: UpdateRequestDto, userId: string): Promise<PurchaseRequest> {
146	    const request = await this.findById(id);
147	
148	    if (request.status !== RequestStatus.DRAFT) {
149	      throw new BadRequestException('Can only edit requests in DRAFT status');
150	    }
151	
152	    if (dto.title !== undefined) request.title = dto.title;
153	    if (dto.description !== undefined) request.description = dto.description;
154	    if (dto.supplierId !== undefined) request.supplierId = dto.supplierId;
155	
156	    if (dto.lineItems !== undefined) {
157	      // Remove old line items
158	      await this.lineItemRepo.delete({ requestId: id });
159	
160	      request.lineItems = dto.lineItems.map((li) => {
161	        const item = new PurchaseRequestLineItem();
162	        item.requestId = id;
163	        item.itemDescription = li.itemDescription;
164	        item.quantity = li.quantity;
165	        item.unitPrice = li.unitPrice;
166	        item.totalPrice = Number((li.quantity * li.unitPrice).toFixed(2));
167	        item.catalogItemId = li.catalogItemId ?? null;
168	        return item;
169	      });
170	
171	      const totalAmount = request.lineItems.reduce((sum, li) => sum + Number(li.totalPrice), 0);
172	      request.totalAmount = Number(totalAmount.toFixed(2));
173	      request.approvalTier = this.calculateApprovalTier(request.totalAmount);
174	    }
175	
176	    await this.requestRepo.save(request);
177	    return this.findById(id);
178	  }
179	
180	  async submit(id: string, userId: string): Promise<PurchaseRequest> {
181	    return this.dataSource.transaction(async (manager) => {
182	      const request = await manager.findOne(PurchaseRequest, {
183	        where: { id },
184	        relations: ['lineItems'],
185	      });
186	
187	      if (!request) throw new NotFoundException('Purchase request not found');
188	      if (request.status !== RequestStatus.DRAFT) {
189	        throw new BadRequestException('Can only submit requests in DRAFT status');
190	      }
191	      if (!request.lineItems || request.lineItems.length === 0) {
192	        throw new BadRequestException('Cannot submit a request with no line items');
193	      }
194	
195	      // Recalculate total and tier
196	      const totalAmount = request.lineItems.reduce((sum, li) => sum + Number(li.totalPrice), 0);
197	      request.totalAmount = Number(totalAmount.toFixed(2));
198	      request.approvalTier = this.calculateApprovalTier(request.totalAmount);
199	
200	      if (request.approvalTier === 0) {
201	        // Auto-approve
202	        request.status = RequestStatus.APPROVED;
203	        await manager.save(request);
204	
205	        await this.auditService.log(userId, AuditAction.PR_AUTO_APPROVED, 'PurchaseRequest', request.id, {
206	          requestNumber: request.requestNumber,
207	          totalAmount: request.totalAmount,
208	        });
209	
210	        await this.notificationService.emit(
211	          request.requestedBy,
212	          NotificationType.REQUEST_APPROVED,
213	          'Request Auto-Approved',
214	          `Your purchase request ${request.requestNumber} has been automatically approved.`,
215	          { type: 'PurchaseRequest', id: request.id },
216	        );
217	
218	        // Auto-generate a draft PO
219	        const fullRequest = await this.findById(request.id);
220	        await this.purchaseOrdersService.generateFromRequest(fullRequest, userId);
221	      } else {
222	        request.status = RequestStatus.PENDING_APPROVAL;
223	        await manager.save(request);
224	
225	        await this.auditService.log(userId, AuditAction.PR_SUBMITTED, 'PurchaseRequest', request.id, {
226	          requestNumber: request.requestNumber,
227	          totalAmount: request.totalAmount,
228	          approvalTier: request.approvalTier,
229	        });
230	
231	        await this.notificationService.emit(
232	          request.requestedBy,
233	          NotificationType.SYSTEM_ALERT,
234	          'Request Pending Approval',
235	          `Your purchase request ${request.requestNumber} has been submitted and is awaiting approval (tier ${request.approvalTier}).`,
236	          { type: 'PurchaseRequest', id: request.id },
237	        );
238	      }
239	
240	      return this.findById(request.id);
241	    });
242	  }
243	
244	  async processApproval(
245	    requestId: string,
246	    dto: ApprovalActionDto,
247	    approverId: string,
248	  ): Promise<PurchaseRequest> {
249	    return this.dataSource.transaction(async (manager) => {
250	      const request = await manager.findOne(PurchaseRequest, {
251	        where: { id: requestId },
252	        relations: ['approvals'],
253	      });
254	
255	      if (!request) throw new NotFoundException('Purchase request not found');
256	      if (request.status !== RequestStatus.PENDING_APPROVAL) {
257	        throw new BadRequestException('Request is not pending approval');
258	      }
259	      if (request.requestedBy === approverId) {
260	        throw new ForbiddenException('Cannot approve your own request');
261	      }
262	
263	      // Check if this user already approved this request
264	      const alreadyApproved = request.approvals.some(
265	        (a) => a.approverId === approverId && a.action === ApprovalAction.APPROVE,
266	      );
267	      if (alreadyApproved) {
268	        throw new BadRequestException('You have already approved this request');
269	      }
270	
271	      // Record the approval/rejection
272	      const approval = manager.create(Approval, {
273	        requestId,
274	        approverId,
275	        action: dto.action,
276	        comments: dto.comments ?? null,
277	      });
278	      await manager.save(approval);
279	
280	      if (dto.action === ApprovalAction.REJECT) {
281	        request.status = RequestStatus.REJECTED;
282	        await manager.save(request);
283	
284	        await this.auditService.log(approverId, AuditAction.PR_REJECTED, 'PurchaseRequest', request.id, {
285	          requestNumber: request.requestNumber,
286	          comments: dto.comments,
287	        });
288	
289	        await this.notificationService.emit(
290	          request.requestedBy,
291	          NotificationType.REQUEST_REJECTED,
292	          'Request Rejected',
293	          `Your purchase request ${request.requestNumber} has been rejected.${dto.comments ? ` Reason: ${dto.comments}` : ''}`,
294	          { type: 'PurchaseRequest', id: request.id },
295	        );
296	      } else {
297	        // Count total approvals (including the one we just added)
298	        const approvalCount =
299	          request.approvals.filter((a) => a.action === ApprovalAction.APPROVE).length + 1;
300	        const requiredApprovals = request.approvalTier === 2 ? 2 : 1;
301	
302	        if (approvalCount >= requiredApprovals) {
303	          request.status = RequestStatus.APPROVED;
304	          await manager.save(request);
305	
306	          await this.auditService.log(approverId, AuditAction.PR_APPROVED, 'PurchaseRequest', request.id, {
307	            requestNumber: request.requestNumber,
308	            approvalCount,
309	            requiredApprovals,
310	          });
311	
312	          await this.notificationService.emit(
313	            request.requestedBy,
314	            NotificationType.REQUEST_APPROVED,
315	            'Request Approved',
316	            `Your purchase request ${request.requestNumber} has been fully approved.`,
317	            { type: 'PurchaseRequest', id: request.id },
318	          );
319	
320	          // Generate draft PO on full approval
321	          const fullRequest = await this.findById(request.id);
322	          await this.purchaseOrdersService.generateFromRequest(fullRequest, approverId);
323	        } else {
324	          // Still needs more approvals
325	          await this.auditService.log(approverId, AuditAction.PR_APPROVED, 'PurchaseRequest', request.id, {
326	            requestNumber: request.requestNumber,
327	            approvalCount,
328	            requiredApprovals,
329	            partial: true,
330	          });
331	
332	          await this.notificationService.emit(
333	            request.requestedBy,
334	            NotificationType.SYSTEM_ALERT,
335	            'Partial Approval Received',
336	            `Purchase request ${request.requestNumber} has received ${approvalCount} of ${requiredApprovals} required approvals.`,
337	            { type: 'PurchaseRequest', id: request.id },
338	          );
339	        }
340	      }
341	
342	      return this.findById(requestId);
343	    });
