346	  async cancel(id: string, userId: string): Promise<PurchaseRequest> {
347	    const request = await this.findById(id);
348	    if (request.status === RequestStatus.CANCELLED || request.status === RequestStatus.APPROVED) {
349	      throw new BadRequestException('Cannot cancel a request that is already approved or cancelled');
350	    }
351	
352	    request.status = RequestStatus.CANCELLED;
353	    await this.requestRepo.save(request);
354	
355	    await this.auditService.log(userId, AuditAction.PR_CANCELLED, 'PurchaseRequest', request.id, {
356	      requestNumber: request.requestNumber,
357	    });
