362	  async getApprovalQueue(query: QueryRequestsDto) {
363	    // Returns all PENDING_APPROVAL requests for the approval queue
364	    const page = parseInt(query.page || '1', 10);
365	    const limit = Math.min(parseInt(query.limit || '20', 10), 100);
366	    const skip = (page - 1) * limit;
367	
368	    const [data, total] = await this.requestRepo.findAndCount({
369	      where: { status: RequestStatus.PENDING_APPROVAL },
370	      relations: ['requester', 'supplier', 'lineItems', 'approvals', 'approvals.approver'],
371	      order: { createdAt: 'ASC' },
372	      skip,
373	      take: limit,
374	    });
375	
376	    return {
377	      data,
378	      meta: { page, limit, total, totalPages: Math.ceil(total / limit) },
379	    };
380	  }
