383	
384	  async ingestLowStockAlert(
385	    dto: {
386	      title: string;
387	      supplierId?: string;
388	      items: { description: string; quantity: number; unitPrice: number }[];
389	      notes?: string;
390	    },
391	    requestedBy: string,
392	  ): Promise<PurchaseRequest> {
393	    if (!dto.items || dto.items.length === 0) {
394	      throw new BadRequestException('Low-stock alert must include at least one item');
395	    }
396	
397	    const createDto: CreateRequestDto = {
398	      title: dto.title,
399	      supplierId: dto.supplierId,
400	      description: dto.notes
401	        ? `[Low-Stock Alert] ${dto.notes}`
402	        : '[Low-Stock Alert] Automatically generated from stock monitoring',
403	      lineItems: dto.items.map((item) => ({
404	        itemDescription: item.description,
405	        quantity: item.quantity,
406	        unitPrice: item.unitPrice,
407	      })),
408	    };
409	
410	    const request = await this.create(createDto, requestedBy);
411	    const submitted = await this.submit(request.id, requestedBy);
412	
413	    await this.auditService.log(
414	      requestedBy,
415	      AuditAction.STOCK_ALERT_INGESTED,
416	      'PurchaseRequest',
417	      submitted.id,
418	      {
419	        requestNumber: submitted.requestNumber,
420	        totalAmount: submitted.totalAmount,
421	        itemCount: dto.items.length,
422	        source: 'low-stock-alert',
423	      },
424	    );
425	
426	    // Notify all procurement managers
427	    const managers: Array<{ id: string }> = await this.dataSource.query(
428	      `SELECT id FROM users WHERE role = 'PROCUREMENT_MANAGER' AND "isActive" = true`,
429	    );
430	    for (const mgr of managers) {
431	      await this.notificationService.emit(
432	        mgr.id,
433	        NotificationType.SYSTEM_ALERT,
434	        'Low-Stock Alert: New Purchase Request',
435	        `A low-stock alert created request ${submitted.requestNumber} for ${dto.items.length} ` +
436	          `item(s) totalling $${submitted.totalAmount}. ` +
437	          `${submitted.status === 'APPROVED' ? 'Auto-approved.' : 'Awaiting approval.'}`,
438	        { type: 'PurchaseRequest', id: submitted.id },
439	      );
440	    }
441	
442	    return submitted;
443	  }
