1	import { Injectable, UnauthorizedException, BadRequestException } from '@nestjs/common';
2	import { JwtService } from '@nestjs/jwt';
3	import { InjectRepository } from '@nestjs/typeorm';
4	import { Repository, LessThan, Not } from 'typeorm';
5	import * as bcrypt from 'bcrypt';
6	import * as crypto from 'crypto';
7	import { UsersService } from '../users/users.service';
8	import { User } from '../users/user.entity';
9	import { Session } from './session.entity';
10	
11	const SESSION_TIMEOUT_MS =
12	  (parseInt(process.env.SESSION_TIMEOUT_MINUTES || '30', 10)) * 60 * 1000;
13	
14	@Injectable()
15	export class AuthService {
16	  constructor(
17	    private readonly usersService: UsersService,
18	    private readonly jwtService: JwtService,
19	    @InjectRepository(Session)
20	    private readonly sessionsRepository: Repository<Session>,
21	    @InjectRepository(User)
22	    private readonly usersRepository: Repository<User>,
23	  ) {}
24	
25	  async validateUser(username: string, password: string): Promise<User> {
26	    const user = await this.usersService.findByUsername(username);
27	    if (!user || !user.isActive) {
28	      throw new UnauthorizedException('Invalid credentials');
29	    }
30	    const valid = await bcrypt.compare(password, user.passwordHash);
31	    if (!valid) {
32	      throw new UnauthorizedException('Invalid credentials');
33	    }
34	    return user;
35	  }
36	
37	  async login(user: User) {
38	    const payload = { sub: user.id, username: user.username, role: user.role };
39	    const accessToken = this.jwtService.sign(payload);
40	
41	    const refreshToken = crypto.randomBytes(48).toString('hex');
42	    const now = new Date();
43	
44	    const session = this.sessionsRepository.create({
45	      userId: user.id,
46	      refreshToken,
47	      expiresAt: new Date(now.getTime() + SESSION_TIMEOUT_MS),
48	      lastActivityAt: now,
49	    });
50	    await this.sessionsRepository.save(session);
51	
52	    return {
53	      accessToken,
54	      refreshToken,
55	      user: {
56	        id: user.id,
57	        username: user.username,
58	        role: user.role,
59	        mustChangePassword: user.mustChangePassword,
60	      },
61	    };
62	  }
63	
64	  async refresh(refreshToken: string) {
65	    const session = await this.sessionsRepository.findOne({
66	      where: { refreshToken },
67	      relations: ['user'],
68	    });
69	
70	    if (!session) {
71	      throw new UnauthorizedException('Invalid refresh token');
72	    }
73	
74	    const now = new Date();
75	    const inactivityMs = now.getTime() - session.lastActivityAt.getTime();
76	
77	    if (inactivityMs > SESSION_TIMEOUT_MS || session.expiresAt < now) {
78	      await this.sessionsRepository.remove(session);
79	      throw new UnauthorizedException('Session expired');
80	    }
81	
82	    // Rotate the refresh token on every use
83	    const newRefreshToken = crypto.randomBytes(48).toString('hex');
84	    session.refreshToken = newRefreshToken;
85	    session.lastActivityAt = now;
86	    session.expiresAt = new Date(now.getTime() + SESSION_TIMEOUT_MS);
87	    await this.sessionsRepository.save(session);
88	
89	    const user = session.user;
90	    const payload = { sub: user.id, username: user.username, role: user.role };
91	    const accessToken = this.jwtService.sign(payload);
92	
93	    return {
94	      accessToken,
95	      refreshToken: newRefreshToken,
96	      user: {
97	        id: user.id,
98	        username: user.username,
99	        role: user.role,
100	        mustChangePassword: user.mustChangePassword,
101	      },
102	    };
103	  }
104	
105	  async changePassword(
106	    userId: string,
107	    currentPassword: string,
108	    newPassword: string,
109	    currentRefreshToken: string,
110	  ): Promise<void> {
111	    const user = await this.usersRepository.findOne({ where: { id: userId } });
112	    if (!user) throw new UnauthorizedException('User not found');
113	
114	    const valid = await bcrypt.compare(currentPassword, user.passwordHash);
115	    if (!valid) throw new BadRequestException('Current password is incorrect');
116	
117	    if (currentPassword === newPassword) {
118	      throw new BadRequestException('New password must differ from current password');
119	    }
120	
121	    const newHash = await bcrypt.hash(newPassword, 12);
122	    await this.usersRepository.update(userId, {
123	      passwordHash: newHash,
124	      mustChangePassword: false,
125	    });
126	
127	    // Invalidate all sessions for this user except the current one
128	    await this.sessionsRepository.delete({
129	      userId,
130	      refreshToken: Not(currentRefreshToken),
131	    });
132	  }
133	
134	  async logout(refreshToken: string): Promise<void> {
135	    await this.sessionsRepository.delete({ refreshToken });
136	  }
137	
138	  async cleanExpiredSessions(): Promise<void> {
139	    await this.sessionsRepository.delete({
140	      expiresAt: LessThan(new Date()),
141	    });
142	  }
143	}
