1	import { test, expect } from '@playwright/test';
2	
3	/**
4	 * Procurement lifecycle E2E test — API level.
5	 *
6	 * Tests the core business flow end-to-end:
7	 *   Purchase Request → Approval → PO (auto-generated) → Issue → Receipt → Return
8	 *
9	 * Uses Playwright's request fixture (HTTP API calls, no browser).
10	 * Runs against the E2E backend on port 3101 via Vite proxy on port 3100.
11	 *
12	 * Prerequisites (same as login.spec.ts):
13	 *   - Demo seed loaded (npm run seed:demo in repo/server)
14	 *   - Server compiled and running (Playwright starts it via webServer)
15	 *
16	 * Demo users used:
17	 *   - demo_admin  (ADMINISTRATOR) — creates requests, issues POs, handles returns
18	 *   - demo_pm     (PROCUREMENT_MANAGER, isSupervisor=true) — approves tier-1 requests
19	 *   - demo_clerk  (WAREHOUSE_CLERK) — creates receipts
20	 */
21	
22	const BASE = 'http://localhost:3101/api';
23	
24	async function login(request: Parameters<typeof test>[1] extends { request: infer R } ? R : never, username: string, password: string): Promise<string> {
25	  const res = await request.post(`${BASE}/auth/login`, {
26	    data: { username, password },
27	  });
28	  expect(res.status()).toBe(200);
29	  const body = await res.json();
30	  return body.accessToken as string;
31	}
32	
33	function authHeader(token: string) {
34	  return { Authorization: `Bearer ${token}` };
35	}
36	
37	test.describe('Procurement lifecycle', () => {
38	  test('happy path: request → supervisor approval → PO → receipt → return', async ({ request }) => {
39	    // ── Step 1: Login ─────────────────────────────────────────────────────────
40	    const adminToken = await login(request, process.env.E2E_ADMIN_USER ?? 'demo_admin', process.env.E2E_ADMIN_PASS ?? 'Demo1234!');
41	    const pmToken = await login(request, 'demo_pm', 'Demo1234!');
42	    const clerkToken = await login(request, 'demo_clerk', 'Demo1234!');
43	
44	    // ── Step 2: Create purchase request (tier-1: $1,500) ─────────────────────
45	    const prRes = await request.post(`${BASE}/procurement/requests`, {
46	      headers: authHeader(adminToken),
47	      data: {
48	        title: 'E2E Lifecycle Test — Fertilizer Restock',
49	        description: 'Automated lifecycle test',
50	        lineItems: [
51	          { itemDescription: 'NPK Fertilizer 10kg', quantity: 10, unitPrice: 150.00 },
52	        ],
53	      },
54	    });
55	    expect(prRes.status()).toBe(201);
56	    const pr = await prRes.json();
57	    expect(pr.status).toBe('DRAFT');
58	    expect(pr.approvalTier).toBe(1);
59	
60	    const prId: string = pr.id;
61	
62	    // ── Step 3: Submit for approval ───────────────────────────────────────────
63	    const submitRes = await request.post(`${BASE}/procurement/requests/${prId}/submit`, {
