43	
44	  private async generatePoNumber(): Promise<string> {
45	    const result = await this.dataSource.query(`SELECT nextval('po_number_seq') as seq`);
46	    const seq = parseInt(result[0].seq, 10);
47	    const year = new Date().getFullYear();
48	    return `PO-${year}-${String(seq).padStart(5, '0')}`;
49	  }
