95	  async findAll(query: QueryPosDto) {
96	    const page = parseInt(query.page || '1', 10);
97	    const limit = Math.min(parseInt(query.limit || '20', 10), 100);
98	    const skip = (page - 1) * limit;
99	
100	    const where: FindOptionsWhere<PurchaseOrder> = {};
101	    if (query.status) where.status = query.status;
102	    if (query.supplierId) where.supplierId = query.supplierId;
103	    if (query.dateFrom && query.dateTo) {
104	      where.createdAt = Between(new Date(query.dateFrom), new Date(query.dateTo)) as any;
105	    } else if (query.dateFrom) {
106	      where.createdAt = MoreThanOrEqual(new Date(query.dateFrom)) as any;
107	    } else if (query.dateTo) {
108	      where.createdAt = LessThanOrEqual(new Date(query.dateTo)) as any;
109	    }
110	
111	    const sortBy = query.sortBy || 'createdAt';
112	    const sortOrder = (query.sortOrder?.toUpperCase() === 'ASC' ? 'ASC' : 'DESC') as 'ASC' | 'DESC';
113	    const allowedSorts = ['poNumber', 'totalAmount', 'status', 'createdAt', 'issuedAt'];
114	    const orderField = allowedSorts.includes(sortBy) ? sortBy : 'createdAt';
115	
116	    const [data, total] = await this.poRepo.findAndCount({
117	      where,
118	      relations: ['supplier', 'request', 'lineItems'],
119	      order: { [orderField]: sortOrder },
120	      skip,
121	      take: limit,
122	    });
123	
124	    return {
125	      data,
126	      meta: { page, limit, total, totalPages: Math.ceil(total / limit) },
127	    };
128	  }
