247	  async updateStatusAfterReceiving(
248	    id: string,
249	    userId: string,
250	    status: PoStatus.PARTIALLY_RECEIVED | PoStatus.FULLY_RECEIVED,
251	  ): Promise<void> {
252	    await this.poRepo.update(id, { status });
