258	  // Supplier portal — only POs belonging to the supplier
259	  async findForSupplier(supplierId: string, query: QueryPosDto) {
260	    const page = parseInt(query.page || '1', 10);
261	    const limit = Math.min(parseInt(query.limit || '20', 10), 50);
262	    const skip = (page - 1) * limit;
263	
264	    const visibleStatuses = [
265	      PoStatus.ISSUED,
266	      PoStatus.PARTIALLY_RECEIVED,
267	      PoStatus.FULLY_RECEIVED,
268	      PoStatus.CLOSED,
269	    ];
270	
271	    const qb = this.poRepo
272	      .createQueryBuilder('po')
273	      .leftJoinAndSelect('po.lineItems', 'lineItems')
274	      .leftJoinAndSelect('po.supplier', 'supplier')
275	      .where('po.supplierId = :supplierId', { supplierId })
276	      .andWhere('po.status IN (:...statuses)', { statuses: visibleStatuses })
277	      .orderBy('po.createdAt', 'DESC')
278	      .skip(skip)
279	      .take(limit);
280	
281	    if (query.status && visibleStatuses.includes(query.status as PoStatus)) {
282	      qb.andWhere('po.status = :status', { status: query.status });
283	    }
284	
285	    const [data, total] = await qb.getManyAndCount();
286	    return { data, meta: { page, limit, total, totalPages: Math.ceil(total / limit) } };
287	  }
288	
289	  async findByIdForSupplier(id: string, supplierId: string): Promise<PurchaseOrder> {
290	    const visibleStatuses = [
291	      PoStatus.ISSUED,
292	      PoStatus.PARTIALLY_RECEIVED,
293	      PoStatus.FULLY_RECEIVED,
294	      PoStatus.CLOSED,
295	    ];
296	
297	    const po = await this.poRepo.findOne({
298	      where: { id, supplierId },
299	      relations: ['supplier', 'lineItems'],
300	    });
301	
302	    if (!po || !visibleStatuses.includes(po.status)) {
303	      throw new NotFoundException('Purchase order not found');
304	    }
305	    return po;
306	  }
307	}
