89	  private canViewArticle(article: Article, userId: string, userRole: string): boolean {
90	    if (userRole === Role.ADMINISTRATOR) return true;
91	    if (article.status === ArticleStatus.ARCHIVED) return false;
92	    if (article.status === ArticleStatus.STOREWIDE) return true;
93	    if (article.status === ArticleStatus.SPECIALIST_ONLY && userRole === Role.PLANT_CARE_SPECIALIST)
94	      return true;
95	    if (article.status === ArticleStatus.DRAFT && article.authorId === userId) return true;
96	    return false;
97	  }
