144	  async update(id: string, userId: string, userRole: string, dto: UpdateArticleDto): Promise<Article> {
145	    const article = await this.articleRepo.findOne({ where: { id } });
146	    if (!article) throw new NotFoundException('Article not found');
147	    if (article.status === ArticleStatus.ARCHIVED)
148	      throw new ForbiddenException('Cannot edit an archived article');
149	
150	    // Specialists may only edit their own draft articles; promotion stays admin-controlled.
151	    if (userRole === Role.PLANT_CARE_SPECIALIST) {
152	      if (article.authorId !== userId)
153	        throw new ForbiddenException('Specialists may only edit their own articles');
154	      if (article.status !== ArticleStatus.DRAFT)
155	        throw new ForbiddenException('Specialists may only edit draft articles');
156	    }
157	
158	    await this.dataSource.transaction(async (manager) => {
159	      if (dto.title !== undefined) article.title = dto.title;
160	      if (dto.category !== undefined) article.category = dto.category;
161	      if (dto.content !== undefined) article.content = dto.content;
162	      if (dto.tags !== undefined) article.tags = dto.tags;
163	
164	      await manager.save(Article, article);
165	
166	      // Get next version number
167	      const maxResult = await manager
168	        .createQueryBuilder()
169	        .select('MAX(av."versionNumber")', 'max')
170	        .from(ArticleVersion, 'av')
171	        .where('av."articleId" = :id', { id })
172	        .getRawOne<{ max: string }>();
173	      const nextVersion = (parseInt(maxResult?.max ?? '0', 10) || 0) + 1;
174	
175	      const v = manager.create(ArticleVersion, {
176	        articleId: id,
177	        versionNumber: nextVersion,
178	        title: article.title,
179	        content: article.content,
180	        changeSummary: dto.changeSummary ?? null,
181	        createdBy: userId,
182	      });
183	      const savedV = await manager.save(ArticleVersion, v);
184	      await manager.update(Article, id, { currentVersionId: savedV.id });
185	    });
186	
187	    const fingerprint = this.dataQuality.generateFingerprint([article.title]);
188	    await this.articleRepo.update(id, { fingerprint });
189	    this.dataQuality.checkForDuplicates('Article', id, fingerprint).catch(() => undefined);
190	
191	    await this.auditService.log(userId, AuditAction.ARTICLE_UPDATED, 'Article', id, {
192	      title: article.title,
193	    });
194	
195	    return this.findById(id, userId, userRole);
196	  }
