198	  async promote(id: string, userId: string, dto: PromoteArticleDto): Promise<Article> {
199	    const article = await this.articleRepo.findOne({ where: { id } });
200	    if (!article) throw new NotFoundException('Article not found');
201	
202	    const prevStatus = article.status;
203	    await this.articleRepo.update(id, { status: dto.status });
204	
205	    const action =
206	      dto.status === ArticleStatus.ARCHIVED
207	        ? AuditAction.ARTICLE_ARCHIVED
208	        : AuditAction.ARTICLE_PROMOTED;
209	
210	    await this.auditService.log(userId, action, 'Article', id, {
211	      title: article.title,
212	      previousStatus: prevStatus,
213	      newStatus: dto.status,
214	    });
215	
216	    if (
217	      article.authorId &&
218	      (dto.status === ArticleStatus.STOREWIDE || dto.status === ArticleStatus.SPECIALIST_ONLY)
219	    ) {
220	      const audience =
221	        dto.status === ArticleStatus.STOREWIDE ? 'all staff' : 'plant care specialists';
222	      await this.notificationService.emit(
223	        article.authorId,
224	        NotificationType.ARTICLE_PUBLISHED,
225	        'Article Published',
226	        `Your article "${article.title}" has been published and is now visible to ${audience}.`,
227	        { type: 'Article', id },
228	      );
229	    }
230	
231	    return this.findById(id, userId, Role.ADMINISTRATOR);
232	  }
