236	  async findAll(userId: string, userRole: string, query: QueryArticlesDto) {
237	    const page = parseInt(query.page || '1', 10);
238	    const limit = Math.min(parseInt(query.limit || '20', 10), 100);
239	    const skip = (page - 1) * limit;
240	
241	    const qb = this.articleRepo
242	      .createQueryBuilder('a')
243	      .leftJoinAndSelect('a.author', 'author')
244	      .orderBy('a.updatedAt', 'DESC')
245	      .skip(skip)
246	      .take(limit);
247	
248	    this.buildVisibilityCondition(qb, userId, userRole);
249	
250	    if (query.search) {
251	      qb.andWhere(
252	        '(a.title ILIKE :search OR a.content ILIKE :search)',
253	        { search: `%${query.search}%` },
254	      );
255	    }
256	    if (query.category) qb.andWhere('a.category = :category', { category: query.category });
257	    if (query.status && userRole === Role.ADMINISTRATOR)
258	      qb.andWhere('a.status = :status', { status: query.status });
259	    if (query.tag)
260	      qb.andWhere(':tag = ANY(a.tags)', { tag: query.tag });
261	
262	    const [data, total] = await qb.getManyAndCount();
263	    return { data, meta: { page, limit, total, totalPages: Math.ceil(total / limit) } };
264	  }
