1	import { Injectable, Logger, NotFoundException, BadRequestException } from '@nestjs/common';
2	import { InjectRepository } from '@nestjs/typeorm';
3	import { Repository, DataSource, EntityManager } from 'typeorm';
4	import { DuplicateCandidate } from './entities/duplicate-candidate.entity';
5	import { EntityMapping } from './entities/entity-mapping.entity';
6	import { DuplicateCandidateStatus } from '../common/enums/duplicate-candidate-status.enum';
7	
8	const FUZZY_THRESHOLD = 0.90;
9	const AUTO_MERGE_THRESHOLD = 0.97;
10	
11	export interface DataQualityIssue {
12	  type:
13	    | 'MISSING_SUPPLIER_EMAIL'
14	    | 'MISSING_PAYMENT_TERMS'
15	    | 'DUPLICATE_SUPPLIER'
16	    | 'OUTLIER_PRICING';
17	  entityType: string;
18	  entityId: string;
19	  label: string;
20	  detail: string;
21	}
22	
23	export interface DataQualityReport {
24	  checkedAt: Date;
25	  issues: DataQualityIssue[];
26	  counts: {
27	    missingEmail: number;
28	    missingPaymentTerms: number;
29	    duplicateSuppliers: number;
30	    outlierPricing: number;
31	  };
32	}
33	
34	@Injectable()
35	export class DataQualityService {
36	  private readonly logger = new Logger(DataQualityService.name);
37	  private lastReport: DataQualityReport | null = null;
38	
39	  constructor(
40	    @InjectRepository(DuplicateCandidate)
41	    private readonly dupRepo: Repository<DuplicateCandidate>,
42	    @InjectRepository(EntityMapping)
43	    private readonly mappingRepo: Repository<EntityMapping>,
44	    private readonly dataSource: DataSource,
45	  ) {}
46	
47	  // ── Fingerprint ───────────────────────────────────────────────────────────
48	
49	  generateFingerprint(parts: (string | null | undefined)[]): string {
50	    return parts
51	      .filter((p): p is string => typeof p === 'string' && p.length > 0)
52	      .map((p) =>
53	        p
54	          .toLowerCase()
55	          .trim()
56	          .replace(/[^a-z0-9\s]/g, ' ')
57	          .replace(/\s+/g, ' ')
58	          .trim(),
59	      )
60	      .join('|');
61	  }
62	
63	  // ── Duplicate detection ───────────────────────────────────────────────────
64	
65	  /**
66	   * Checks for duplicates for a single entity.
67	   * When called inside a transaction (e.g., from runDedupScan), pass the
68	   * EntityManager so writes participate in the transaction and are rolled back
69	   * atomically on failure.
70	   */
71	  async checkForDuplicates(
72	    entityType: 'Supplier' | 'Article',
73	    id: string,
74	    fingerprint: string,
75	    manager?: EntityManager,
76	  ): Promise<void> {
77	    if (!fingerprint) return;
78	
79	    const table = entityType === 'Supplier' ? 'suppliers' : 'articles';
80	    const db = manager ?? this.dataSource;
81	    const dupRepo = manager
82	      ? manager.getRepository(DuplicateCandidate)
83	      : this.dupRepo;
84	
85	    const rows: Array<{ id: string; score: string }> = await db.query(
86	      `
87	      SELECT id, similarity(fingerprint, $1) AS score
88	      FROM ${table}
89	      WHERE id != $2
90	        AND fingerprint IS NOT NULL
91	        AND similarity(fingerprint, $1) >= $3
92	      ORDER BY score DESC
93	      LIMIT 10
94	      `,
95	      [fingerprint, id, FUZZY_THRESHOLD],
96	    );
97	
98	    for (const row of rows) {
99	      const score = parseFloat(row.score);
100	      // Canonical pair ordering (smaller UUID first) prevents duplicate pairs
101	      const [sourceId, targetId] = id < row.id ? [id, row.id] : [row.id, id];
102	
103	      const existing = await dupRepo.findOne({
104	        where: { entityType, sourceId, targetId },
105	      });
106	
107	      if (existing) {
108	        // Update score if improved
109	        if (score > Number(existing.similarityScore)) {
110	          await dupRepo.update(existing.id, {
111	            similarityScore: score,
112	            isAutoMergeCandidate: score >= AUTO_MERGE_THRESHOLD,
113	            status:
114	              existing.status === DuplicateCandidateStatus.DISMISSED
115	                ? DuplicateCandidateStatus.DISMISSED
116	                : DuplicateCandidateStatus.PENDING_REVIEW,
117	          });
118	        }
119	        continue;
120	      }
121	
122	      await dupRepo.save({
123	        entityType,
124	        sourceId,
125	        targetId,
126	        similarityScore: score,
127	        isAutoMergeCandidate: score >= AUTO_MERGE_THRESHOLD,
128	        status: DuplicateCandidateStatus.PENDING_REVIEW,
129	      });
130	
131	      this.logger.log(
132	        `Duplicate candidate: ${entityType} ${sourceId} ↔ ${targetId} (${(score * 100).toFixed(1)}%)`,
133	      );
134	    }
135	  }
136	
137	  // ── Merge ─────────────────────────────────────────────────────────────────
138	
139	  async mergeDuplicate(candidateId: string, adminId: string): Promise<void> {
140	    const candidate = await this.dupRepo.findOne({ where: { id: candidateId } });
141	    if (!candidate) throw new NotFoundException('Duplicate candidate not found');
142	    if (candidate.status !== DuplicateCandidateStatus.PENDING_REVIEW) {
143	      throw new BadRequestException(`Candidate is already ${candidate.status}`);
144	    }
145	
146	    // sourceId = primary (kept), targetId = secondary (soft-deleted)
147	    const primaryId = candidate.sourceId;
148	    const secondaryId = candidate.targetId;
149	
150	    await this.dataSource.transaction(async (manager) => {
151	      if (candidate.entityType === 'Supplier') {
152	        await this.mergeSuppliers(manager, primaryId, secondaryId);
153	      } else if (candidate.entityType === 'Article') {
154	        await this.mergeArticles(manager, primaryId, secondaryId);
155	      }
156	
157	      // Record the mapping
158	      await manager.save(EntityMapping, {
159	        entityType: candidate.entityType,
160	        oldId: secondaryId,
161	        newId: primaryId,
162	        mergedBy: adminId,
163	      });
164	
165	      // Mark candidate as merged
166	      await manager.update(DuplicateCandidate, candidateId, {
167	        status: DuplicateCandidateStatus.MERGED,
168	        reviewedBy: adminId,
169	        reviewedAt: new Date(),
170	      });
171	
172	      // Dismiss other candidates that involve the secondary record
173	      await manager
174	        .createQueryBuilder()
175	        .update(DuplicateCandidate)
176	        .set({
177	          status: DuplicateCandidateStatus.DISMISSED,
178	          reviewedBy: adminId,
179	          reviewedAt: new Date(),
180	        })
181	        .where(
182	          '("sourceId" = :sid OR "targetId" = :sid) AND status = :status AND id != :cid',
183	          {
184	            sid: secondaryId,
185	            status: DuplicateCandidateStatus.PENDING_REVIEW,
186	            cid: candidateId,
187	          },
188	        )
189	        .execute();
190	    });
191	  }
