193	  private async mergeSuppliers(
194	    manager: EntityManager,
195	    primaryId: string,
196	    secondaryId: string,
197	  ): Promise<void> {
198	    // Rewire FKs to primary
199	    await manager.query(
200	      `UPDATE purchase_requests SET "supplierId" = $1 WHERE "supplierId" = $2`,
201	      [primaryId, secondaryId],
202	    );
203	    await manager.query(
204	      `UPDATE purchase_orders SET "supplierId" = $1 WHERE "supplierId" = $2`,
205	      [primaryId, secondaryId],
206	    );
207	    await manager.query(
208	      `UPDATE return_authorizations SET "supplierId" = $1 WHERE "supplierId" = $2`,
209	      [primaryId, secondaryId],
210	    );
211	    await manager.query(
212	      `UPDATE funds_ledger_entries SET "supplierId" = $1 WHERE "supplierId" = $2`,
213	      [primaryId, secondaryId],
214	    );
215	    // Soft-delete secondary
216	    await manager.query(`UPDATE suppliers SET "isActive" = false WHERE id = $1`, [secondaryId]);
217	  }
