219	  private async mergeArticles(
220	    manager: EntityManager,
221	    primaryId: string,
222	    secondaryId: string,
223	  ): Promise<void> {
224	    // Rewire FKs to primary
225	    await manager.query(
226	      `UPDATE article_versions SET "articleId" = $1 WHERE "articleId" = $2`,
227	      [primaryId, secondaryId],
228	    );
229	    // Upsert favorites (avoid PK conflict: skip if user already favorited primary)
230	    await manager.query(
231	      `INSERT INTO user_favorites ("userId", "articleId", "createdAt")
232	       SELECT "userId", $1, "createdAt"
233	       FROM user_favorites
234	       WHERE "articleId" = $2
235	         AND "userId" NOT IN (SELECT "userId" FROM user_favorites WHERE "articleId" = $1)`,
236	      [primaryId, secondaryId],
237	    );
238	    await manager.query(`DELETE FROM user_favorites WHERE "articleId" = $1`, [secondaryId]);
239	    // Archive secondary
240	    await manager.query(`UPDATE articles SET status = 'ARCHIVED' WHERE id = $1`, [secondaryId]);
241	  }
