243	  // ── Dismiss ───────────────────────────────────────────────────────────────
244	
245	  async dismissDuplicate(candidateId: string, adminId: string): Promise<void> {
246	    const candidate = await this.dupRepo.findOne({ where: { id: candidateId } });
247	    if (!candidate) throw new NotFoundException('Duplicate candidate not found');
248	    if (candidate.status !== DuplicateCandidateStatus.PENDING_REVIEW) {
249	      throw new BadRequestException(`Candidate is already ${candidate.status}`);
250	    }
251	    await this.dupRepo.update(candidateId, {
