258	  // ── Query duplicates ──────────────────────────────────────────────────────
259	
260	  async getDuplicates(
261	    status?: string,
262	    entityType?: string,
263	  ): Promise<DuplicateCandidate[]> {
264	    const qb = this.dupRepo
265	      .createQueryBuilder('dc')
266	      .leftJoinAndSelect('dc.reviewer', 'reviewer')
267	      .orderBy('dc.similarityScore', 'DESC')
268	      .addOrderBy('dc.createdAt', 'DESC');
269	
270	    if (status) qb.andWhere('dc.status = :status', { status });
271	    if (entityType) qb.andWhere('dc.entityType = :entityType', { entityType });
272	
273	    return qb.getMany();
