294	    const [target] = await this.dataSource.query(
295	      `SELECT ${columns} FROM ${table} WHERE id = $1`,
296	      [candidate.targetId],
297	    );
298	
299	    return {
300	      candidate,
301	      source: source ?? null,
302	      target: target ?? null,
303	    };
304	  }
305	
306	  // ── Data quality checks ───────────────────────────────────────────────────
307	
308	  async runQualityChecks(): Promise<DataQualityReport> {
309	    this.logger.log('Running data quality checks…');
310	    const issues: DataQualityIssue[] = [];
311	
312	    // 1. Suppliers missing email
313	    const missingEmail: Array<{ id: string; name: string }> = await this.dataSource.query(
314	      `SELECT id, name FROM suppliers WHERE "isActive" = true AND (email IS NULL OR email = '')`,
315	    );
316	    for (const s of missingEmail) {
317	      issues.push({
318	        type: 'MISSING_SUPPLIER_EMAIL',
319	        entityType: 'Supplier',
320	        entityId: s.id,
321	        label: s.name,
322	        detail: 'Supplier is missing an email address.',
323	      });
324	    }
325	
326	    // 2. Suppliers missing payment terms (null or default is fine; flag if customTermsDescription is non-null but paymentTerms is null)
327	    //    Actually per spec: "Missing required fields: email, payment terms"
328	    //    Since paymentTerms has a DB default, let's flag suppliers where paymentTerms is NULL
329	    const missingPaymentTerms: Array<{ id: string; name: string }> = await this.dataSource.query(
330	      `SELECT id, name FROM suppliers WHERE "isActive" = true AND "paymentTerms" IS NULL`,
331	    );
332	    for (const s of missingPaymentTerms) {
333	      issues.push({
334	        type: 'MISSING_PAYMENT_TERMS',
335	        entityType: 'Supplier',
336	        entityId: s.id,
337	        label: s.name,
338	        detail: 'Supplier is missing payment terms.',
339	      });
340	    }
341	
342	    // 3. Duplicate suppliers by name similarity (not already flagged by fingerprint dedup)
343	    const dupSuppliers: Array<{ id1: string; name1: string; id2: string; name2: string; score: string }> =
344	      await this.dataSource.query(`
345	        SELECT
346	          s1.id AS id1, s1.name AS name1,
347	          s2.id AS id2, s2.name AS name2,
348	          similarity(s1.name, s2.name) AS score
349	        FROM suppliers s1
350	        JOIN suppliers s2 ON s1.id < s2.id
351	        WHERE s1."isActive" = true AND s2."isActive" = true
352	          AND similarity(s1.name, s2.name) >= 0.80
353	        ORDER BY score DESC
354	        LIMIT 20
355	      `);
356	    for (const d of dupSuppliers) {
357	      issues.push({
358	        type: 'DUPLICATE_SUPPLIER',
359	        entityType: 'Supplier',
360	        entityId: d.id1,
361	        label: `${d.name1} / ${d.name2}`,
362	        detail: `Name similarity: ${(parseFloat(d.score) * 100).toFixed(1)}%. Possible duplicate with supplier ${d.id2}.`,
363	      });
364	    }
365	
366	    // 4. Outlier pricing: PO line items with unit price > 3× median for the same description
367	    const outliers: Array<{ id: string; description: string; unitPrice: string; median: string; poId: string }> =
368	      await this.dataSource.query(`
369	        WITH medians AS (
370	          SELECT
371	            description,
372	            PERCENTILE_CONT(0.5) WITHIN GROUP (ORDER BY "unitPrice") AS median_price
373	          FROM purchase_order_line_items
374	          GROUP BY description
375	          HAVING COUNT(*) >= 2
376	        )
377	        SELECT li.id, li.description, li."unitPrice", li."poId", m.median_price AS median
378	        FROM purchase_order_line_items li
379	        JOIN medians m ON m.description = li.description
380	        WHERE li."unitPrice" > m.median_price * 3
381	        ORDER BY (li."unitPrice" / m.median_price) DESC
382	        LIMIT 50
383	      `);
384	    for (const o of outliers) {
385	      issues.push({
386	        type: 'OUTLIER_PRICING',
387	        entityType: 'PurchaseOrderLineItem',
388	        entityId: o.id,
389	        label: o.description,
390	        detail: `Unit price $${parseFloat(o.unitPrice).toFixed(2)} is ${(parseFloat(o.unitPrice) / parseFloat(o.median)).toFixed(1)}× the median ($${parseFloat(o.median).toFixed(2)}) on PO ${o.poId}.`,
391	      });
392	    }
393	
394	    const report: DataQualityReport = {
395	      checkedAt: new Date(),
396	      issues,
397	      counts: {
398	        missingEmail: missingEmail.length,
399	        missingPaymentTerms: missingPaymentTerms.length,
400	        duplicateSuppliers: dupSuppliers.length,
401	        outlierPricing: outliers.length,
402	      },
403	    };
404	
405	    this.lastReport = report;
406	    this.logger.log(`Data quality check complete: ${issues.length} issue(s) found.`);
407	    return report;
408	  }
409	
410	  async getLastQualityReport(): Promise<DataQualityReport | null> {
411	    return this.lastReport;
412	  }
413	
414	  // ── Full dedup scan ───────────────────────────────────────────────────────
415	
416	  /**
417	   * Runs a full dedup scan wrapped in a single database transaction.
418	   * If any write fails, the entire scan for this attempt is rolled back,
419	   * preventing partial writes that could corrupt duplicate-candidate state
420	   * across retry attempts.
421	   */
422	  async runDedupScan(): Promise<void> {
423	    this.logger.log('Running full dedup scan…');
424	
425	    let supplierCount = 0;
426	    let articleCount = 0;
427	
428	    await this.dataSource.transaction(async (manager) => {
429	      // Scan suppliers that have a fingerprint
430	      const suppliers: Array<{ id: string; fingerprint: string }> = await manager.query(
431	        `SELECT id, fingerprint FROM suppliers WHERE fingerprint IS NOT NULL AND "isActive" = true`,
432	      );
433	      supplierCount = suppliers.length;
434	      for (const s of suppliers) {
435	        await this.checkForDuplicates('Supplier', s.id, s.fingerprint, manager);
436	      }
437	
438	      // Scan articles that have a fingerprint
439	      const articles: Array<{ id: string; fingerprint: string }> = await manager.query(
440	        `SELECT id, fingerprint FROM articles WHERE fingerprint IS NOT NULL AND status != 'ARCHIVED'`,
441	      );
442	      articleCount = articles.length;
443	      for (const a of articles) {
444	        await this.checkForDuplicates('Article', a.id, a.fingerprint, manager);
445	      }
446	    });
447	
448	    this.logger.log(
449	      `Dedup scan complete: checked ${supplierCount} suppliers, ${articleCount} articles.`,
450	    );
451	  }
452	
453	  async getPendingCount(): Promise<number> {
454	    return this.dupRepo.count({ where: { status: DuplicateCandidateStatus.PENDING_REVIEW } });
455	  }
456	}
