29	/** Build a minimal mock Repository with chainable query builder. */
30	function makeRepo(overrides: Partial<{
31	  getRawManyResult: Array<{ recipientId: string }>;
32	  getCountResult: number;
33	  findResult: Notification[];
34	  executeResult: void;
35	}> = {}) {
36	  const executeResult = overrides.executeResult;
37	  const execute = jest.fn(async () => executeResult);
38	
39	  const qb = {
40	    select: jest.fn().mockReturnThis(),
41	    where: jest.fn().mockReturnThis(),
42	    andWhere: jest.fn().mockReturnThis(),
43	    update: jest.fn().mockReturnThis(),
44	    set: jest.fn().mockReturnThis(),
45	    whereInIds: jest.fn().mockReturnThis(),
46	    getRawMany: jest.fn(async () => overrides.getRawManyResult ?? []),
47	    getCount: jest.fn(async () => overrides.getCountResult ?? 0),
48	    execute,
49	  };
50	
51	  return {
52	    createQueryBuilder: jest.fn(() => qb),
53	    find: jest.fn(async () => overrides.findResult ?? []),
54	    save: jest.fn(async (data: unknown) => data),
55	    update: jest.fn(async () => undefined),
56	    count: jest.fn(async () => 0),
57	    findOne: jest.fn(async () => null),
58	    findOneOrFail: jest.fn(async () => null),
59	    _qb: qb,       // exposed for assertions
60	    _execute: execute,
61	  };
62	}
