80	
81	    const module: TestingModule = await Test.createTestingModule({
82	      providers: [
83	        NotificationService,
84	        { provide: getRepositoryToken(Notification), useValue: notifRepo },
85	        { provide: getRepositoryToken(NotificationPreference), useValue: prefRepo },
86	        { provide: getRepositoryToken(NotificationThrottle), useValue: throttleRepo },
