95	  // ── drainQueue — no-op path ───────────────────────────────────────────────
96	
97	  it('does nothing when there are no queued notifications', async () => {
98	    notifRepo._qb.getRawMany.mockResolvedValue([]);
99	    await service.drainQueue();
100	    expect(notifRepo._execute).not.toHaveBeenCalled();
101	  });
102	
103	  // ── drainQueue — direct repo path (no manager) ───────────────────────────
104	
105	  it('delivers queued notifications via injected repo when no manager is given', async () => {
106	    notifRepo._qb.getRawMany.mockResolvedValue([{ recipientId: 'u1' }]);
107	    notifRepo._qb.getCount.mockResolvedValue(0); // 0 recent → capacity = 20
108	    notifRepo.find.mockResolvedValue([makeNotification({ id: 'n1' })]);
109	
110	    await service.drainQueue();
