141	      expect(notifRepo.createQueryBuilder).not.toHaveBeenCalled();
142	      expect(notifRepo.find).not.toHaveBeenCalled();
143	      expect(manager.getRepository).toHaveBeenCalledWith(Notification);
144	      expect(txRepo._execute).toHaveBeenCalledTimes(1);
145	    });
