163	  // ── Rollback simulation ───────────────────────────────────────────────────
164	
165	  describe('rollback on failure (simulated via transaction mock)', () => {
166	    /**
167	     * Simulates the full transactional drain as it runs inside the scheduler:
168	     *   dataSource.transaction(manager => notificationService.drainQueue(manager))
169	     *
170	     * The mock transaction tracks "committed" writes.  If fn() throws the
171	     * mock rolls back by clearing the write log, demonstrating no partial state.
172	     */
173	    it('no writes are committed when drainQueue throws mid-execution', async () => {
174	      const committedWrites: string[] = [];
175	      let rolledBack = false;
176	
177	      // Build a txRepo whose execute() records a write then throws
178	      const failingQb = {
179	        select: jest.fn().mockReturnThis(),
180	        where: jest.fn().mockReturnThis(),
181	        andWhere: jest.fn().mockReturnThis(),
182	        update: jest.fn().mockReturnThis(),
183	        set: jest.fn().mockReturnThis(),
184	        whereInIds: jest.fn().mockReturnThis(),
185	        getRawMany: jest.fn(async () => [{ recipientId: 'u1' }]),
186	        getCount: jest.fn(async () => 0),
187	        execute: jest.fn(async () => {
188	          committedWrites.push('u1:delivered');
189	          throw new Error('DB failure during delivery');
190	        }),
191	      };
192	      const failingRepo = {
193	        createQueryBuilder: jest.fn(() => failingQb),
194	        find: jest.fn(async () => [makeNotification({ id: 'n1' })]),
195	      } as unknown as Repository<Notification>;
196	
197	      const manager = {
198	        getRepository: jest.fn(() => failingRepo),
199	      } as unknown as EntityManager;
200	
201	      // Simulate dataSource.transaction: roll back writes on error
202	      dataSource.transaction.mockImplementationOnce(
203	        async (fn: (m: EntityManager) => Promise<void>) => {
204	          try {
205	            await fn(manager);
206	          } catch {
207	            // Transaction rolled back — discard any in-progress writes
208	            committedWrites.length = 0;
209	            rolledBack = true;
210	            // Swallowed here so runJob can handle the error via its own catch
211	          }
212	        },
213	      );
214	
215	      // Run as the scheduler would
216	      await dataSource.transaction((m: EntityManager) => service.drainQueue(m));
217	
218	      expect(rolledBack).toBe(true);
219	      expect(committedWrites).toHaveLength(0); // no partial state persists
220	    });
221	
222	    it('retry attempt runs a fresh transaction after rollback', async () => {
223	      let attemptCount = 0;
224	
225	      // First attempt: fail; second attempt: succeed
226	      dataSource.transaction.mockImplementation(
227	        async (fn: (m: EntityManager) => Promise<void>) => {
228	          attemptCount++;
229	          const txRepo = makeRepo({
230	            getRawManyResult: [{ recipientId: 'u1' }],
231	            getCountResult: 0,
232	            findResult: [makeNotification()],
233	          });
234	          const manager = { getRepository: jest.fn(() => txRepo) } as unknown as EntityManager;
235	
236	          if (attemptCount === 1) {
237	            try { await fn(manager); } catch { /* rolled back */ }
238	            throw new Error('first attempt failed');
239	          }
240	          // Second attempt succeeds
241	          await fn(manager);
242	        },
243	      );
244	
245	      // withRetry will call the fn up to 3 times; simulate 2 attempts here
246	      let calls = 0;
247	      const drainFn = async (): Promise<void> => {
248	        calls++;
249	        await dataSource.transaction((m: EntityManager) => service.drainQueue(m));
250	      };
251	
252	      // First call throws, second succeeds
253	      try { await drainFn(); } catch { /* first attempt */ }
254	      await drainFn(); // second attempt — should succeed
255	
256	      expect(calls).toBe(2);
257	      expect(attemptCount).toBe(2); // two independent transactions
258	    });
259	  });
260	});
