25	const SUBMITTABLE = [ReturnStatus.DRAFT];
26	const CANCELLABLE = [ReturnStatus.DRAFT, ReturnStatus.SUBMITTED, ReturnStatus.APPROVED];
27	
28	@Injectable()
29	export class ReturnsService {
30	  constructor(
31	    @InjectRepository(ReturnAuthorization)
32	    private readonly raRepo: Repository<ReturnAuthorization>,
33	    @InjectRepository(ReturnLineItem)
