1	import { Injectable, NotFoundException, ConflictException } from '@nestjs/common';
2	import { InjectRepository } from '@nestjs/typeorm';
3	import { Repository, DataSource } from 'typeorm';
4	import { SearchSynonym } from './entities/search-synonym.entity';
5	import { SearchHistory } from './entities/search-history.entity';
6	import { Article } from '../knowledge-base/entities/article.entity';
7	import { ArticleStatus } from '../common/enums/article-status.enum';
8	import { Role } from '../common/enums/role.enum';
9	import { CreateSynonymDto } from './dto/create-synonym.dto';
10	import { UpdateSynonymDto } from './dto/update-synonym.dto';
11	
12	export interface SearchResult {
13	  id: string;
14	  title: string;
15	  slug: string;
16	  category: string;
17	  status: string;
18	  tags: string[];
19	  author: { id: string; firstName: string; lastName: string } | null;
20	  headline: string;
21	  rank: number;
22	  updatedAt: Date;
23	}
24	
25	export interface SimilarArticle {
26	  id: string;
27	  title: string;
28	  slug: string;
29	  category: string;
30	  status: string;
31	  tags: string[];
32	  score: number;
33	}
34	
35	@Injectable()
36	export class SearchService {
37	  constructor(
38	    @InjectRepository(SearchSynonym)
39	    private readonly synonymRepo: Repository<SearchSynonym>,
40	    @InjectRepository(SearchHistory)
41	    private readonly historyRepo: Repository<SearchHistory>,
42	    @InjectRepository(Article)
43	    private readonly articleRepo: Repository<Article>,
44	    private readonly dataSource: DataSource,
45	  ) {}
46	
47	  // ── Synonym expansion ─────────────────────────────────────────────────────
48	
49	  private async expandQuery(rawQuery: string): Promise<string[]> {
50	    const terms = rawQuery
51	      .toLowerCase()
52	      .replace(/[^a-z0-9\s]/g, ' ')
53	      .split(/\s+/)
54	      .filter(Boolean);
55	
56	    const expanded = new Set<string>(terms);
57	    if (terms.length === 0) return [];
58	
59	    // Forward lookup: term → synonyms
60	    const forward = await this.synonymRepo
61	      .createQueryBuilder('s')
62	      .where('LOWER(s.term) = ANY(:terms)', { terms })
63	      .getMany();
64	
65	    for (const row of forward) {
66	      row.synonyms.forEach((syn) =>
67	        syn.toLowerCase().split(/\s+/).filter(Boolean).forEach((t) => expanded.add(t)),
68	      );
69	    }
70	
71	    // Reverse lookup: synonym → term (and all its synonyms)
72	    const reverse = await this.synonymRepo
73	      .createQueryBuilder('s')
74	      .where(
75	        `EXISTS (SELECT 1 FROM unnest(s.synonyms) syn WHERE LOWER(syn) = ANY(:terms))`,
76	        { terms },
77	      )
78	      .getMany();
79	
80	    for (const row of reverse) {
81	      expanded.add(row.term.toLowerCase());
82	      row.synonyms.forEach((syn) =>
83	        syn.toLowerCase().split(/\s+/).filter(Boolean).forEach((t) => expanded.add(t)),
84	      );
85	    }
86	
87	    return Array.from(expanded);
88	  }
89	
90	  // ── Search ────────────────────────────────────────────────────────────────
91	
92	  async search(
93	    userId: string,
94	    userRole: string,
95	    q: string,
96	    category?: string,
97	    tags?: string,
98	  ): Promise<{ data: SearchResult[]; total: number; expandedTerms: string[] }> {
99	    const trimmed = q?.trim() ?? '';
100	    if (!trimmed) return { data: [], total: 0, expandedTerms: [] };
101	
102	    const expandedTerms = await this.expandQuery(trimmed);
103	    if (expandedTerms.length === 0) return { data: [], total: 0, expandedTerms: [] };
104	
105	    // tsquery: each term with prefix matching, OR-combined
106	    const tsquery = expandedTerms.map((t) => `${t}:*`).join(' | ');
107	
108	    const values: unknown[] = [tsquery]; // $1
109	    let idx = 2;
110	
111	    // Visibility clause
112	    let visibilitySql: string;
113	    if (userRole === Role.ADMINISTRATOR) {
114	      visibilitySql = `a.status != $${idx++}`;
115	      values.push(ArticleStatus.ARCHIVED);
116	    } else if (userRole === Role.PLANT_CARE_SPECIALIST) {
117	      visibilitySql = `(a.status = $${idx++} OR a.status = $${idx++} OR (a.status = $${idx++} AND a."authorId" = $${idx++}))`;
118	      values.push(ArticleStatus.STOREWIDE, ArticleStatus.SPECIALIST_ONLY, ArticleStatus.DRAFT, userId);
119	    } else {
120	      visibilitySql = `(a.status = $${idx++} OR (a.status = $${idx++} AND a."authorId" = $${idx++}))`;
121	      values.push(ArticleStatus.STOREWIDE, ArticleStatus.DRAFT, userId);
122	    }
123	
124	    let sql = `
125	      SELECT
126	        a.id,
127	        a.title,
128	        a.slug,
129	        a.category,
130	        a.status,
131	        a.tags,
132	        a."updatedAt",
133	        a."authorId",
134	        u."firstName",
135	        u."lastName",
136	        ts_rank(a.search_vector, to_tsquery('english', $1)) AS rank,
137	        ts_headline('english', a.title || ' ' || a.content,
138	          to_tsquery('english', $1),
139	          'MaxWords=30, MinWords=10, StartSel=<mark>, StopSel=</mark>'
140	        ) AS headline
141	      FROM articles a
142	      LEFT JOIN users u ON u.id = a."authorId"
143	      WHERE ${visibilitySql}
144	        AND a.search_vector @@ to_tsquery('english', $1)
145	    `;
146	
147	    if (category) {
148	      sql += ` AND a.category = $${idx++}`;
149	      values.push(category);
150	    }
151	
152	    if (tags) {
153	      sql += ` AND $${idx++} = ANY(a.tags)`;
154	      values.push(tags);
155	    }
156	
157	    sql += ` ORDER BY rank DESC, a."updatedAt" DESC LIMIT 50`;
158	
159	    const rows: Record<string, unknown>[] = await this.dataSource.query(sql, values);
160	
161	    const data: SearchResult[] = rows.map((r) => ({
162	      id: r['id'] as string,
163	      title: r['title'] as string,
164	      slug: r['slug'] as string,
165	      category: r['category'] as string,
166	      status: r['status'] as string,
167	      tags: r['tags'] as string[],
168	      author: r['authorId']
169	        ? {
170	            id: r['authorId'] as string,
171	            firstName: r['firstName'] as string,
172	            lastName: r['lastName'] as string,
173	          }
174	        : null,
175	      headline: r['headline'] as string,
176	      rank: parseFloat(r['rank'] as string),
177	      updatedAt: r['updatedAt'] as Date,
178	    }));
179	
180	    // Save history non-blocking
181	    this.saveHistory(userId, trimmed, data.length).catch(() => undefined);
182	
183	    return { data, total: data.length, expandedTerms };
184	  }
185	
186	  // ── Similar articles ──────────────────────────────────────────────────────
187	
188	  async findSimilar(
189	    articleId: string,
190	    userId: string,
191	    userRole: string,
192	  ): Promise<SimilarArticle[]> {
193	    const article = await this.articleRepo.findOne({ where: { id: articleId } });
194	    if (!article) throw new NotFoundException('Article not found');
195	
196	    let visibilitySql: string;
197	    if (userRole === Role.ADMINISTRATOR) {
198	      visibilitySql = `a.status != '${ArticleStatus.ARCHIVED}'`;
199	    } else if (userRole === Role.PLANT_CARE_SPECIALIST) {
200	      visibilitySql = `a.status IN ('${ArticleStatus.STOREWIDE}','${ArticleStatus.SPECIALIST_ONLY}')`;
201	    } else {
202	      visibilitySql = `a.status = '${ArticleStatus.STOREWIDE}'`;
203	    }
204	
205	    const rows: Record<string, unknown>[] = await this.dataSource.query(
206	      `
207	      SELECT
208	        a.id,
209	        a.title,
210	        a.slug,
211	        a.category,
212	        a.status,
213	        a.tags,
214	        (
215	          similarity(a.title, $1) * 2.0 +
216	          (
217	            SELECT count(*)::float
218	            FROM unnest(a.tags) t
219	            WHERE t = ANY($2::text[])
220	          ) * 1.5
221	        ) AS score
222	      FROM articles a
223	      WHERE a.id != $3
224	        AND ${visibilitySql}
225	        AND (
226	          similarity(a.title, $1) > 0.1
227	          OR EXISTS (SELECT 1 FROM unnest(a.tags) t WHERE t = ANY($2::text[]))
228	        )
229	      ORDER BY score DESC
230	      LIMIT 5
231	      `,
232	      [article.title, article.tags, articleId],
233	    );
234	
235	    return rows.map((r) => ({
236	      id: r['id'] as string,
237	      title: r['title'] as string,
238	      slug: r['slug'] as string,
239	      category: r['category'] as string,
240	      status: r['status'] as string,
241	      tags: r['tags'] as string[],
242	      score: parseFloat(r['score'] as string),
243	    }));
244	  }
245	
246	  // ── Search history ────────────────────────────────────────────────────────
247	
248	  private async saveHistory(userId: string, query: string, resultCount: number): Promise<void> {
249	    await this.historyRepo.save({ userId, query, resultCount });
250	    // Prune to last 50
251	    await this.dataSource.query(
252	      `DELETE FROM search_history
253	       WHERE "userId" = $1
254	         AND id NOT IN (
255	           SELECT id FROM search_history
256	           WHERE "userId" = $1
257	           ORDER BY "searchedAt" DESC
258	           LIMIT 50
259	         )`,
260	      [userId],
261	    );
262	  }
263	
264	  async getHistory(userId: string, q?: string): Promise<SearchHistory[]> {
265	    const qb = this.historyRepo
266	      .createQueryBuilder('h')
267	      .where('h.userId = :userId', { userId })
268	      .orderBy('h.searchedAt', 'DESC')
269	      .limit(50);
270	
271	    if (q) {
272	      qb.andWhere('h.query ILIKE :q', { q: `${q}%` });
273	    }
274	
275	    return qb.getMany();
276	  }
277	
278	  // ── Synonyms CRUD ─────────────────────────────────────────────────────────
279	
280	  async findAllSynonyms(): Promise<SearchSynonym[]> {
281	    return this.synonymRepo.find({ order: { term: 'ASC' } });
282	  }
283	
284	  async findSynonym(id: string): Promise<SearchSynonym> {
285	    const s = await this.synonymRepo.findOne({ where: { id } });
286	    if (!s) throw new NotFoundException('Synonym not found');
287	    return s;
288	  }
289	
290	  async createSynonym(dto: CreateSynonymDto): Promise<SearchSynonym> {
291	    const existing = await this.synonymRepo.findOne({
292	      where: { term: dto.term.toLowerCase() },
293	    });
294	    if (existing) throw new ConflictException(`Synonym for "${dto.term}" already exists`);
295	    return this.synonymRepo.save({
296	      term: dto.term.toLowerCase(),
297	      synonyms: dto.synonyms.map((s) => s.toLowerCase()),
298	    });
299	  }
300	
301	  async updateSynonym(id: string, dto: UpdateSynonymDto): Promise<SearchSynonym> {
302	    const s = await this.findSynonym(id);
303	    if (dto.term !== undefined) s.term = dto.term.toLowerCase();
304	    if (dto.synonyms !== undefined) s.synonyms = dto.synonyms.map((v) => v.toLowerCase());
305	    return this.synonymRepo.save(s);
306	  }
307	
308	  async deleteSynonym(id: string): Promise<void> {
309	    await this.findSynonym(id);
310	    await this.synonymRepo.delete(id);
311	  }
312	}
