1	/**
2	 * E2E smoke flow: login as SUPPLIER → redirected to /supplier-portal → portal
3	 * renders supplier profile data.
4	 *
5	 * Uses real AuthProvider + Login page + SupplierPortal page (API modules mocked).
6	 * Exercises the full frontend auth → route-guard → protected-page pipeline
7	 * for the SUPPLIER role.
8	 */
9	import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
10	import { render, screen, waitFor, act } from '@testing-library/react';
11	import userEvent from '@testing-library/user-event';
12	import { MemoryRouter, Route, Routes } from 'react-router-dom';
13	
14	import { AuthProvider } from '../contexts/AuthContext';
15	import { ProtectedRoute } from '../components/ProtectedRoute';
16	import { Login } from '../pages/Login';
17	import { SupplierPortal } from '../pages/SupplierPortal';
18	
19	// ── Mock API modules used by SupplierPortal and its child components ──────────
20	
21	vi.mock('../api/suppliers', () => ({
22	  fetchSupplierPortalProfile: vi.fn(),
23	}));
24	
25	vi.mock('../api/purchase-orders', () => ({
26	  fetchPortalPos: vi.fn(),
27	}));
28	
29	vi.mock('../api/returns', () => ({
30	  fetchPortalReturns: vi.fn(),
31	}));
32	
33	import { fetchSupplierPortalProfile } from '../api/suppliers';
34	import { fetchPortalPos } from '../api/purchase-orders';
35	import { fetchPortalReturns } from '../api/returns';
36	
37	const mockFetchProfile = vi.mocked(fetchSupplierPortalProfile);
38	const mockFetchPos = vi.mocked(fetchPortalPos);
39	const mockFetchReturns = vi.mocked(fetchPortalReturns);
40	
41	// ── Render helper: Login + protected /supplier-portal ─────────────────────────
42	
43	function renderSupplierApp() {
44	  return render(
45	    <MemoryRouter initialEntries={['/login']}>
46	      <AuthProvider>
47	        <Routes>
48	          <Route path="/login" element={<Login />} />
49	          <Route path="/unauthorized" element={<div>Unauthorized</div>} />
50	          <Route path="/change-password" element={<div>Change Password</div>} />
51	          <Route
52	            path="/supplier-portal"
53	            element={
54	              <ProtectedRoute roles={['SUPPLIER']}>
55	                <SupplierPortal />
56	              </ProtectedRoute>
57	            }
58	          />
59	          {/* Role-redirect targets for non-SUPPLIER logins */}
60	          <Route path="/admin" element={<div>Admin Dashboard</div>} />
61	          <Route path="/procurement" element={<div>Procurement Dashboard</div>} />
62	          <Route path="/warehouse" element={<div>Warehouse Dashboard</div>} />
63	          <Route path="/plant-care" element={<div>Plant Care Dashboard</div>} />
64	        </Routes>
65	      </AuthProvider>
66	    </MemoryRouter>,
67	  );
68	}
69	
70	// ── Tests ─────────────────────────────────────────────────────────────────────
71	
72	describe('Supplier portal smoke flow', () => {
73	  beforeEach(() => {
74	    vi.stubGlobal('fetch', vi.fn());
75	
76	    // Stable API mock responses for SupplierPortal child components
77	    mockFetchProfile.mockResolvedValue({
78	      id: 'sup-1',
79	      name: 'Acme Corp',
80	      contactName: 'Alice Smith',
81	      email: 'alice@acme.com',
82	      phone: '555-0100',
83	      address: '1 Acme Way',
84	      paymentTerms: 'NET_30',
85	      customTermsDescription: null,
86	      isActive: true,
87	    } as any);
88	
89	    mockFetchPos.mockResolvedValue({
90	      data: [],
91	      meta: { page: 1, limit: 20, total: 0, totalPages: 0 },
92	    } as any);
93	
94	    mockFetchReturns.mockResolvedValue({
95	      data: [],
96	      meta: { page: 1, limit: 20, total: 0, totalPages: 0 },
97	    } as any);
98	  });
99	
100	  afterEach(() => {
101	    vi.clearAllMocks();
102	    vi.restoreAllMocks();
103	  });
104	
105	  it('login as SUPPLIER → redirected to /supplier-portal → profile renders', async () => {
106	    (fetch as ReturnType<typeof vi.fn>)
107	      // AuthProvider tries to restore session on mount — no existing session
108	      .mockResolvedValueOnce({ ok: false })
109	      // Login POST — returns SUPPLIER user
110	      .mockResolvedValueOnce({
111	        ok: true,
112	        json: async () => ({
113	          accessToken: 'supplier-access-token',
114	          user: {
115	            id: 'u-sup',
116	            username: 'acme_supplier',
117	            role: 'SUPPLIER',
118	            mustChangePassword: false,
119	          },
120	        }),
121	      });
122	
123	    renderSupplierApp();
124	
125	    // Wait for the login form to appear (AuthProvider resolves loading)
126	    await waitFor(() => screen.getByLabelText(/username/i));
127	
128	    // Fill in credentials and submit
129	    await act(async () => {
130	      await userEvent.type(screen.getByLabelText(/username/i), 'acme_supplier');
131	      await userEvent.type(screen.getByLabelText(/password/i), 'password1');
132	      await userEvent.click(screen.getByRole('button', { name: /sign in/i }));
133	    });
134	
135	    // Should navigate to /supplier-portal and render the portal heading
136	    await waitFor(() =>
137	      expect(screen.getByRole('heading', { name: /supplier portal/i })).toBeInTheDocument(),
138	    );
139	
140	    // Supplier profile data should appear
141	    await waitFor(() => expect(screen.getByText('Acme Corp')).toBeInTheDocument());
142	    expect(screen.getByText('Alice Smith')).toBeInTheDocument();
143	    expect(mockFetchProfile).toHaveBeenCalledTimes(1);
144	  });
145	
146	  it('ADMINISTRATOR login does NOT land on /supplier-portal', async () => {
147	    (fetch as ReturnType<typeof vi.fn>)
148	      .mockResolvedValueOnce({ ok: false }) // refresh fails
149	      .mockResolvedValueOnce({
150	        ok: true,
151	        json: async () => ({
152	          accessToken: 'admin-token',
153	          user: {
154	            id: 'u-admin',
155	            username: 'admin',
156	            role: 'ADMINISTRATOR',
157	            mustChangePassword: false,
158	          },
159	        }),
160	      });
161	
162	    renderSupplierApp();
163	
164	    await waitFor(() => screen.getByLabelText(/username/i));
165	
166	    await act(async () => {
167	      await userEvent.type(screen.getByLabelText(/username/i), 'admin');
168	      await userEvent.type(screen.getByLabelText(/password/i), 'adminpass');
169	      await userEvent.click(screen.getByRole('button', { name: /sign in/i }));
170	    });
171	
172	    // ADMINISTRATOR redirects to /admin, NOT /supplier-portal
173	    await waitFor(() =>
174	      expect(screen.getByText('Admin Dashboard')).toBeInTheDocument(),
175	    );
176	
177	    expect(screen.queryByRole('heading', { name: /supplier portal/i })).not.toBeInTheDocument();
178	    // Profile API must not have been called for admin
179	    expect(mockFetchProfile).not.toHaveBeenCalled();
180	  });
181	});
182

