  const ids: {
    adminId?: string;
    specAId?: string;
    specBId?: string;
    clerkId?: string;
    supplierId?: string;
    draftArticleId?: string;
    storewideArticleId?: string;
    specialistOnlyArticleId?: string;
    archivedArticleId?: string;
  } = {};

  // ── Bootstrap ─────────────────────────────────────────────────────────────

  beforeAll(async () => {
